window.recipes = [{"id": "estufa-velas", "title": "Clay Pots and Candles Stove", "category": "tecnologia", "tag": "Heating", "image": "assets/images/estufa.webp", "views": 618000, "summary": "Learn how to build a natural radiant heating system using terracotta pots and small tea lights. Ecological, economical heat without electricity.", "intro": "The pot stove is an ingenious home heater that takes advantage of the principle of thermal inertia and natural convection. Refractory clay absorbs and radiates the heat of candles without consuming electricity. If you are looking for a more powerful option for outdoors, you can see how to build our <a href=\"rocket-stove.html\">Brick Rocket Stove</a>.", "healthBenefit": "Unlike commercial forced air heaters or gas radiators, this stove heats by gentle thermal radiation and inertia of the clay. This prevents extreme dryness of the air (protecting your respiratory mucous membranes and throat) and prevents the dispersion of dust, pollen and mites in suspension, making it ideal for people with asthma or allergies.", "time": "15 minutes", "rawDuration": "Pots: Unlimited", "finalDuration": "Tea lights: 4 hours", "cost": "0.40 €", "metrics": {"economy": 90, "health": 85, "ecosystem": 90}, "shoppingList": [{"name": "Unglazed clay pot (20cm)", "price": "1.50 €"}, {"name": "Clay mace without enamel (15cm)", "price": "1.00 €"}, {"name": "Base plate for clay pot", "price": "0.80 €"}, {"name": "Threaded rod, nuts and washers", "price": "1.20 €"}, {"name": "Vegetable paraffin tea lights (4 units)", "price": "0.40 €"}], "steps": ["Make sure both pots and the base have a clean, aligned center hole.", "Insert the threaded rod through the clay plate that will serve as a firm base for the assembly.", "Place a washer and a nut to secure the rod to the base on both sides of the plate.", "Insert the small pot upside down on the rod and raise it about 2 cm from the base using nuts to allow oxygen flow. Secure it firmly.", "Place the large pot upside down, covering the small one. There must be a space or air chamber between the two. Secure it with an end nut on the end.", "Place 3 or 4 tea lights on the base plate and light them carefully.", "The inner clay bell will accumulate direct heat, and the hot air will flow by convection through the intermediate space, tempering the outer pot to radiate constant heat."], "altUses": ["Aromatherapy diffuser by placing a few drops of pure essential oils on the warm outer pot.", "Rustic ecological heater for small greenhouses to avoid night frosts.", "Decorative outdoor radiant centerpiece."], "extraInfo": "The physics behind this system lies in the transfer of radiant heat. The internal hood absorbs the candle flame (which reaches 800°C at its core) and prevents direct heat loss to the ceiling. The external hood acts as a heat sink that heats the cold air entering from the bottom through natural convection.", "comparisonTable": [{"concepto": "Cost per 4 Hours", "casero": "0.40 € (Candles)", "comercial": "1.50 € (Calefactor 1000W)", "diferencia": "Savings of 73.3%"}, {"concepto": "Environmental Humidity", "casero": "Preserves natural humidity", "comercial": "Dry out the mucosal tract", "diferencia": "Better breathing"}, {"concepto": "Air Currents", "casero": "0% No currents (Radiant)", "comercial": "Moves dust, spores and mites", "diferencia": "Hypoallergenic"}, {"concepto": "Network Autonomy", "casero": "100% Autonomous (Emergency)", "comercial": "Requires mains electricity or gas", "diferencia": "Without cables"}], "subcategory": "calefaccion"}, {"id": "detergente-hiedra", "title": "Ivy and Lavender Liquid Detergent", "category": "hogar", "tag": "Cleaning", "image": "assets/images/detergente.webp", "views": 600000, "summary": "Learn how to make your own concentrated organic detergent from common ivy leaves (rich in natural saponins) and flavored with wild lavender essence.", "intro": "Common ivy (Hedera helix) contains saponins, a natural surfactant that acts as an ecological soap. This homemade detergent does not contain aggressive chemicals, making it ideal for sensitive skin. Combine it with our <a href=\"softener-vinegar.html\">Vinegar and Rosemary Softener</a> to leave your clothes impeccable and soft naturally.", "healthBenefit": "Avoid direct exposure to endocrine disruptors, artificial fragrances and optical brighteners present in commercial detergents. These synthetic compounds are trapped in textile fibers and penetrate the bloodstream through constant dermal contact, being the main cause of outbreaks of atopic dermatitis, contact allergies and respiratory irritations when inhaling perfumes from clothing.", "time": "25 minutes", "rawDuration": "Fresh leaves: 2 weeks", "finalDuration": "Liquid detergent: 6 months", "cost": "0.50 €", "metrics": {"economy": 95, "health": 90, "ecosystem": 100}, "shoppingList": [{"name": "Common ivy leaves (collected)", "price": "0.00 €"}, {"name": "Purified tap water (2 Liters)", "price": "0.05 €"}, {"name": "Pure lavender essential oil (30 drops)", "price": "0.45 €"}], "steps": ["Collect about 60-80 fresh common ivy leaves (avoid those near main roads). Wash them thoroughly in cold water to remove any dirt.", "Chop or crush the leaves lightly with your hands to release the internal saponins of the plant fibers.", "Place the chopped leaves in a large pot with 2 liters of water. Bring to a boil over medium heat.", "Once it boils, reduce the heat and let it simmer for 20 minutes with the pot covered.", "Turn off the heat and let the pot cool completely without uncovering it so it can finish resting (about 3-4 hours). The water will take on a greenish-brown color.", "Strain the resulting liquid using a cotton cloth or fine strainer to remove all vegetable remains.", "Add the 30 drops of lavender essential oil and stir well to homogenize. Pour into a glass or recycled plastic bottle.", "Dosage: Use 150ml (a standard cup) directly into the washing machine drawer for each full load of laundry."], "altUses": ["Biodegradable manual dishwasher by diluting the resulting liquid by 50% with water.", "Foliar cleaner for plants: sprayed on the leaves it acts as a brightener and natural repellent for pests such as aphids.", "Light organic fertilizer: cooked ivy remains can be composted by adding nitrogen to the soil."], "extraInfo": "The saponins in ivy are soluble in hot water and release natural foam when shaken. It is not necessary to add artificial thickeners. For very dirty white clothes, it is recommended to supplement the laundry by adding two tablespoons of sodium percarbonate directly into the washing machine drum.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "0.25 €", "comercial": "3.50 €", "diferencia": "Savings of 92.8%"}, {"concepto": "Chemicals/Sulfates", "casero": "0% (Solo saponina natural)", "comercial": "Synthetic surfactants and PEG", "diferencia": "No allergens"}, {"concepto": "Packaging Waste", "casero": "Zero (Reusable packaging)", "comercial": "Single-use HDPE plastic bottles", "diferencia": "100% Sustainable"}, {"concepto": "Performance (Loads)", "casero": "13 washed per liter", "comercial": "20 washes per liter", "diferencia": "Similar efficiency"}], "subcategory": "limpieza"}, {"id": "nevera-arcilla", "title": "Clay Refrigerator without Electricity (Zeer Refrigerator)", "category": "tecnologia", "tag": "Food", "image": "assets/images/nevera.webp", "views": 420000, "summary": "Build your own handcrafted evaporative cooler by combining two terracotta pots and moist sand. 100% natural, wireless and low-cost food preservation.", "intro": "The Zeer refrigerator is an evaporative structure that allows vegetables, fruits and liquids to be preserved at cool temperatures without electricity. It is ideal for hot, dry climates and works through the laws of thermodynamics, cooling the inner pot as the water contained in the outer sand evaporates through the porous clay.", "healthBenefit": "It keeps food fresh in an environment of constant natural humidity that prevents rapid dehydration of vegetables, preserving their soluble vitamins and antioxidants for longer. In addition, it works with absolute silence (0 dB), eliminating the noise pollution of the commercial electric compressor that disturbs your rest and increases the body's levels of cortisol (the stress hormone).", "time": "30 minutes", "rawDuration": "Pots: Unlimited", "finalDuration": "Wet sand: Daily recharge", "cost": "9.50 €", "metrics": {"economy": 85, "health": 90, "ecosystem": 95}, "shoppingList": [{"name": "Large clay mallet without enamel (40cm)", "price": "5.50 €"}, {"name": "Small unglazed clay pot (30cm)", "price": "3.00 €"}, {"name": "Fine river sand (1 bag)", "price": "0.80 €"}, {"name": "Burlap or thick cotton cloth", "price": "0.20 €"}], "steps": ["Block and tightly seal the drainage holes of both pots with wet clay or cork to prevent sand leaks.", "Place a firm 5cm layer of fine sand in the bottom of the large pot.", "Center the small pot inside the large pot on the initial layer of sand.", "Fill the circular free space between the two pots with fine river sand up to the top edge.", "Carefully pour cold water over the sand until it is completely saturated with moisture, ensuring that no water passes into the small pot inside.", "Place vegetables, fruits or bottles in the interior compartment of the small pot.", "Cover the opening with a previously moistened burlap or thick cotton cloth.", "Place the refrigerator in a shaded and ventilated area. Wet it twice a day to keep the evaporative process active."], "altUses": ["Ecological cooler for drinks and soft drinks for terraces, gardens or camping.", "Chamber for the controlled maturation of artisanal cheeses that require high humidity.", "Long-term storage and preservation of potatoes, garlic and onions in basements."], "extraInfo": "This refrigerator works optimally in climates with low relative humidity. As dry air passes over the moist walls of the outer pot, it causes water to evaporate. This change of state requires energy (latent heat), which is extracted from the interior of the refrigerator, reducing the internal temperature between 5°C and 15°C below the ambient temperature.", "comparisonTable": [{"concepto": "Light Consumption", "casero": "0W (Zero electricity)", "comercial": "150W - 300W continuos", "diferencia": "100% savings"}, {"concepto": "Green Preservation", "casero": "Optimal humidity (without drying out)", "comercial": "Dry cold dehydrates vegetables", "diferencia": "Fresher foods"}, {"concepto": "Acoustic Noise", "casero": "0 dB (Absolute silence)", "comercial": "35-45 dB (Constant Compressor)", "diferencia": "Reduces stress"}, {"concepto": "Chemical Refrigerants", "casero": "Just plain water", "comercial": "HFC gases harmful to the ozone layer", "diferencia": "100% Ecological"}], "subcategory": "alimentos"}, {"id": "repelente-ajo", "title": "Organic Garlic and Neem Oil Repellent", "category": "hogar", "tag": "Food", "image": "assets/images/repelente_ajo.webp", "views": 330000, "summary": "Protect your garden or indoor plants from common pests such as aphids and whiteflies with a natural spray based on fermented garlic and pure Neem oil.", "intro": "Garlic contains powerful organosulfur compounds, such as allicin, which act as an olfactory repellent and natural larvicide. Combined with neem oil (rich in azadirachtin), this organic repellent interrupts the biological cycle of pests without harming pollinating insects (such as bees) or contaminating the substrate with synthetic chemical residues.", "healthBenefit": "Avoid contact and inhalation of commercial insecticides based on pyrethroids and organophosphates, which act as powerful cumulative neurotoxins and endocrine disruptors. By using this natural repellent, you protect your home and your domestic crops from pests without introducing toxic substances that can deposit on the edible leaves or be inhaled by your children or pets.", "time": "20 minutes (Maceration: 24 hours)", "rawDuration": "Neem oil: 1 year", "finalDuration": "Prepared solution: 2 weeks", "cost": "1.10 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Whole head of fresh garlic", "price": "0.40 €"}, {"name": "Pure Pressed Neem Oil (10ml)", "price": "0.50 €"}, {"name": "Biodegradable potassium or neutral soap (10g)", "price": "0.15 €"}, {"name": "Distilled or chlorine-free water (1 Liter)", "price": "0.05 €"}], "steps": ["Shell the entire head of garlic and grind all the peeled cloves together with 500ml of water in a blender until you achieve a fine paste.", "Pour the whipped mixture into a glass jar, seal it, and let it sit at room temperature for 24 hours to ferment and release the allicin.", "Filter the garlic maceration with a cotton cloth or fine gauze, squeezing well to separate all the vegetable pulp that could clog the sprayer.", "Heat the rest of the water (500ml) to lukewarm temperature and dissolve the potassium soap, which will act as an emulsifier for the oil.", "Pour the 10ml of neem oil over the soapy water and whisk vigorously to form a homogeneous emulsion.", "Combine the neem oil emulsion with the strained garlic extract in a spray bottle.", "Apply the mixture by spraying it directly on the leaves (upper and underside) of the garden at dusk, every 7 days as a preventative or every 3 days against active pests."], "altUses": ["Protective barrier against ants and snails by spraying the base of the pots.", "Preventive antifungal disinfectant for floors prone to mold.", "Safe natural insecticide for decorative plants in offices and homes without residual chemical odors."], "extraInfo": "The azadirachtin in neem oil acts by contact and ingestion. It is an analogue of ecdysone (the molting hormone in insects), which blocks the development of larvae and prevents them from reaching their reproductive phase. As it is not a direct broad-spectrum neurotoxic poison, it respects beneficial fauna such as ladybugs and bees if applied when they are not active.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "1.10 €", "comercial": "€14.50 (Commercial pesticide)", "diferencia": "Savings of 92.4%"}, {"concepto": "Harvest Residues", "casero": "0% Persistent residue", "comercial": "Requires security periods of days", "diferencia": "clean food"}, {"concepto": "Pulmonary Toxicity", "casero": "Completely safe and harmless", "comercial": "Toxic by inhalation and contact", "diferencia": "Risk-free"}, {"concepto": "Biodegradability", "casero": "100% Fast on the ground", "comercial": "Persistent in groundwater", "diferencia": "Protect water"}], "subcategory": "alimentos"}, {"id": "filtro-agua", "title": "Carbon and Sand Emergency Water Filter", "category": "tecnologia", "tag": "Agua", "image": "assets/images/filtro_agua.webp", "views": 290000, "summary": "Builds a mechanical biological and chemical filtration system to purify fresh water from natural sources using activated carbon, fine sand and gravel.", "intro": "This filter simulates the natural filtration of water through the subsoil. It uses activated charcoal, fine sand and gravel to retain physical impurities. If you also want to eliminate heavy metals and chemical toxins more effectively, we recommend manufacturing our <a href=\"filtro-biochar.html\">Biochar Water Filter</a>.", "healthBenefit": "Purifies water by eliminating sediments, residual chlorine and pathogens through physical retention, while active carbon adsorbs toxins and heavy metals. By avoiding the exclusive use of chlorine or commercial chemical purification tablets, you reduce the intake of chlorine compounds that irritate and weaken the colonic mucosa and destroy the protective intestinal microbiota.", "time": "25 minutes", "rawDuration": "Loose materials: Unlimited", "finalDuration": "Operating filter: 3 months (then renew carbon)", "cost": "1.50 €", "metrics": {"economy": 95, "health": 90, "ecosystem": 100}, "shoppingList": [{"name": "Large glass container or PET bottle (1.5L)", "price": "0.20 €"}, {"name": "Crushed active charcoal (200g)", "price": "0.80 €"}, {"name": "Fine washed river sand (300g)", "price": "0.20 €"}, {"name": "Gravel or small river stones (300g)", "price": "0.10 €"}, {"name": "Organic cotton or clean cotton cloth", "price": "0.20 €"}], "steps": ["If you use a plastic bottle, cut off the base. If you use a glass container with a spigot, clean it well.", "Place the organic cotton or cloth tightly in the mouth of the container or faucet to act as a final barrier.", "Pour the first layer of finely crushed activated carbon (about 8-10 cm thick). The coal must be well compacted.", "Add the layer of fine sand on top of the charcoal (another 8-10 cm). This layer will trap microscopic impurities.", "Place a layer of coarse sand or fine gravel on top of the river sand.", "Complete the top with medium stones or coarse gravel. This layer will retain leaves, branches and large impurities.", "Pour water and let it drain. Discard the first 2 liters filtered (they will come out black from the charcoal dust). The subsequent water will come out crystal clear and purified."], "altUses": ["Filtration system for rainwater collected for use in domestic irrigation.", "Purifier for small garden ponds or artisanal aquariums.", "Science educational tool to teach the water purification cycle to children."], "extraInfo": "This filter performs physical and chemical filtration. Charcoal has high porosity and a surface area of ​​up to 1000 m² per gram, which attracts and traps organic contaminants, chlorine, herbicides and pesticides through Van der Waals forces. Note: in cases of highly biologically contaminated water, it is recommended to boil the water after filtering it.", "comparisonTable": [{"concepto": "Cost per Filter", "casero": "1.50 €", "comercial": "€35.00 (Pitcher/Commercial Filter)", "diferencia": "Savings of 95.7%"}, {"concepto": "Purification Chemicals", "casero": "0% Natural (Physical/Adsorption)", "comercial": "Chlorine and synthetic resins", "diferencia": "No harsh chemicals"}, {"concepto": "Cartridge Waste", "casero": "Compostables (Sand and coal)", "comercial": "Non-recyclable closed plastic cartridges", "diferencia": "Zero plastic waste"}, {"concepto": "Physical Effectiveness", "casero": "Retains particles > 1 micron", "comercial": "Retains chlorine and sediment", "diferencia": "Equivalent"}], "subcategory": "agua"}, {"id": "deshidratador-solar", "title": "Wooden Solar Food Dehydrator", "category": "tecnologia", "tag": "Food", "image": "assets/images/deshidratador.webp", "views": 250000, "summary": "Learn how to build a passive solar convection dehydrator to preserve surplus crops, fruits and medicinal herbs in a clean and hygienic way.", "intro": "The solar dehydrator is a traditional tool for preserving food for months without resorting to freezing. It consists of a wooden cabin with a dark, sloping base covered by glass that heats the incoming air. Through natural convection, warm air rises through mesh trays, removing moisture from food quickly and protecting it from dust and insects.", "healthBenefit": "Preserves fruits, mushrooms and medicinal plants, keeping their minerals, fiber and most of their water-soluble vitamins and enzymes intact by not exceeding 45°C. Completely avoid the use of commercial industrial chemical preservatives such as sulfur dioxide or sulfites, which are added to commercial dried fruits and cause asthma, allergic reactions and migraines.", "time": "45 minutes", "rawDuration": "Structure: Years", "finalDuration": "Dry foods: 6 to 12 months", "cost": "12.00 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Recycled wood slats and boards", "price": "4.50 €"}, {"name": "Transparent glass or methacrylate sheet", "price": "4.00 €"}, {"name": "Stainless steel or fabric mosquito net", "price": "2.00 €"}, {"name": "Ecological water-based black paint (interior)", "price": "1.00 €"}, {"name": "Hinges and small screws", "price": "0.50 €"}], "steps": ["Build a rectangular wooden box, leaving the top inclined at about 30-40 degrees to optimize solar incidence.", "Paint the inside bottom of the drawer matte black (with ecological paint without heavy metals) to absorb solar radiation and generate heat.", "Make ventilation openings at the bottom (cold air inlet) and at the top (humid air outlet), covering them with a mosquito net to avoid insects.", "Place slats on the inside side walls to serve as rails for the trays to slide.", "Build wooden frames with the stainless steel mosquito net to create the trays where the food will rest.", "Install the clear glass cover on the slanted hinged top to open and close the dehydrator.", "Place the dehydrator facing south in a sunny spot. Place thin slices of fruit (apple, banana, strawberries) on the trays and close the glass."], "altUses": ["Dryer for aromatic and medicinal herbs (chamomile, rosemary, mint) preserving their essential oils.", "Preservative for wild mushrooms collected in autumn.", "Ecological dryer for garden seeds to save them from one year to the next."], "extraInfo": "Solar drying is based on the greenhouse effect. Sunlight passes through the glass and heats the black bottom of the collector, which emits long-wave infrared radiation that cannot escape through the glass. This raises the interior temperature. Hot air decreases its relative humidity and rises, dragging the water vapor released by the food to the outside due to differences in density.", "comparisonTable": [{"concepto": "Energy Expenditure", "casero": "0W (Passive solar energy)", "comercial": "500W per hour (Electric dehydrator)", "diferencia": "100% savings"}, {"concepto": "Chemical Preservation", "casero": "Zero additives or sulfites", "comercial": "Sulfites to preserve bright color", "diferencia": "No allergens"}, {"concepto": "Hygiene and Pests", "casero": "Airtight against flies and dust", "comercial": "N/A (Industrial processing)", "diferencia": "Very hygienic"}, {"concepto": "Drying Temperature", "casero": "Mild (35°C - 45°C) preserves enzymes", "comercial": "High temperatures (destroys vitamins)", "diferencia": "Higher nutritional quality"}], "subcategory": "alimentos"}, {"id": "pasta-dientes", "title": "Clay and Coconut Remineralizing Toothpaste", "category": "cuerpo", "tag": "Hygiene", "image": "assets/images/pasta_dientes.webp", "views": 210000, "summary": "Makes an alkalizing toothpaste free of synthetic fluoride using purifying kaolin (white clay for internal use), baking soda and antibacterial coconut oil.", "intro": "This recipe offers a chemical-free alternative to industrial toothpastes. White clay remineralizes enamel, coconut fights germs and baking soda neutralizes oral acidity. Complete your natural oral hygiene with our <a href=\"mouthwash-clavo.html\">Clove and Cinnamon Antiseptic Mouthwash</a>.", "healthBenefit": "It completely dispenses with synthetic fluoride (associated with systemic toxicity and accumulation of fluorosis in the bones), sodium lauryl sulfate (a highly irritating industrial foaming agent that causes microlesions and mouth ulcers) and microplastics. This natural formula alkalizes oral pH, remineralizes enamel with plant calcium and cleans effectively while respecting the protective oral microbiome.", "time": "10 minutes", "rawDuration": "Clay and ingredients: 1 year", "finalDuration": "Toothpaste: 3 months", "cost": "1.20 €", "metrics": {"economy": 85, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "White clay for internal use (Kaolin) (30g)", "price": "0.50 €"}, {"name": "Organic extra virgin coconut oil (20g)", "price": "0.40 €"}, {"name": "Food grade baking soda (5g)", "price": "0.05 €"}, {"name": "Peppermint essential oil (10 drops)", "price": "0.20 €"}, {"name": "Small glass jar with lid", "price": "0.05 €"}], "steps": ["Mix the white clay (kaolin) and baking soda in a glass, ceramic or wooden bowl. Avoid metal utensils so as not to alter the ionic properties of the clay.", "If the coconut oil is solid, dissolve it in a bain-marie over very low heat until it becomes liquid.", "Pour the warm coconut oil over the dry powder mixture gradually.", "Stir patiently using a wooden or silicone spatula until you achieve a creamy paste consistency.", "Add 10 drops of peppermint essential oil to provide freshness and pleasant flavor. Mix for the last time.", "Transfer the finished paste to the small clean glass jar and cover it.", "Use: Take a small portion (pea size) with a clean spatula or the dry brush itself. Brush gently for 3 minutes and rinse well."], "altUses": ["Direct application on insect bites to soothe itching and disinfect.", "Ultra-gentle, non-abrasive cleaner to restore the shine of silver pieces.", "Emergency armpit deodorant thanks to baking soda and coconut oil."], "extraInfo": "White clay or kaolin is rich in silica and minerals that nourish the gums and support enamel remineralization. Unlike the poor quality calcium carbonate in some commercial pastes, kaolin has an extremely low abrasiveness rating, which protects sensitive tooth enamel. Coconut oil contains lauric acid, which attacks harmful bacteria such as *Streptococcus mutans*.", "comparisonTable": [{"concepto": "Cost per 60ml", "casero": "1.20 €", "comercial": "€4.50 (Organic pasta)", "diferencia": "Savings of 73.3%"}, {"concepto": "Fluorine and Sulfates (SLS)", "casero": "0% No fluoride or irritating SLS", "comercial": "Present as standard ingredients", "diferencia": "Without toxic substances"}, {"concepto": "Gum Protection", "casero": "Soothing and protective formula", "comercial": "SLS dries out and promotes canker sores", "diferencia": "natural protection"}, {"concepto": "Container Type", "casero": "Reusable glass jar", "comercial": "Non-recyclable laminated plastic tube", "diferencia": "Zero Waste"}], "subcategory": "higiene"}, {"id": "jabon-ceniza", "title": "Wood Ash and Olive Leachate Soap", "category": "hogar", "tag": "Cleaning", "image": "assets/images/jabon_ceniza_nuevo.webp", "views": 180000, "summary": "Learn how to make a concentrated liquid or soft soap using the leach obtained from wood ashes and used olive oil.", "intro": "Obtaining soap by leaching ash is one of the oldest chemical techniques of humanity. Hardwood ash is rich in potassium carbonate (potash), an alkaline base that, when reacting with the fatty acids in olive oil, produces saponification. It is an excellent biodegradable soap for washing clothes and floors.", "healthBenefit": "Avoid using commercial gels and soaps that contain strong petrochemical surfactants, formaldehyde-releasing preservatives, and artificially synthesized fragrances. These substances damage the skin's lipid barrier and microbiome, and are absorbed into the bloodstream, potentially acting as potent allergens and hormone disruptors in the body.", "time": "1 hour (Bleach rest: 2 days)", "rawDuration": "Dry ash: Unlimited", "finalDuration": "Liquid soap: 12 months", "cost": "0.80 €", "metrics": {"economy": 95, "health": 90, "ecosystem": 100}, "shoppingList": [{"name": "Sifted hardwood ash (1 kg)", "price": "0.00 €"}, {"name": "Rain or filtered water (4 Liters)", "price": "0.10 €"}, {"name": "Used filtered olive oil (1 Liter)", "price": "0.50 €"}, {"name": "Lemon or rosemary essential oil (20 drops)", "price": "0.20 €"}], "steps": ["Thoroughly sift clean wood ashes from your fireplace to remove unburned pieces of charcoal. Use white ash.", "Mix ash and water in a plastic bucket in a proportion of 1 part ash to 4 parts hot water. Stir well with a wooden stick.", "Let the mixture sit, covered, for 48 hours in a safe place, stirring twice a day. Potassium leachate will concentrate.", "Carefully strain the resulting liquid using a thick cotton cloth to obtain a clean, amber-colored leachate. Wear safety gloves.", "In a stainless steel pot (never aluminum), heat the olive oil to about 60°C.", "Slowly pour the concentrated leachate over the oil while stirring continuously over low heat for about 40 minutes until a thick emulsion is achieved.", "Turn off the heat, let it cool and add the essential oil to flavor. Pour into reused glass bottles or jugs."], "altUses": ["Concentrated biodegradable detergent for laundry in the washing machine or hand wash.", "Disinfectant cleaner for rustic wooden, stone or tile floors.", "Preventive treatment for agricultural pests by diluting it in 2% water to spray leaves."], "extraInfo": "Leaching extracts potassium carbonate from the ash. Saponification with potash results in a soft or liquid soap (potassium soap), unlike caustic soda (sodium hydroxide) which produces hard sodium soaps. Ash potash is extremely friendly to wastewater as it provides useful potassium for soil plants.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "0.20 €", "comercial": "€3.20 (Commercial potassium soap)", "diferencia": "Savings of 93.7%"}, {"concepto": "Origin of Alkali", "casero": "Natural wood ash", "comercial": "Chemically purified caustic potash", "diferencia": "No synthetic chemicals"}, {"concepto": "Impact on the Skin", "casero": "Mild, sulfate free", "comercial": "Irritant foaming agents", "diferencia": "Protects the dermis"}, {"concepto": "Packaging Waste", "casero": "Reusable household jugs", "comercial": "Single-use plastic bottles", "diferencia": "Sustainable"}], "subcategory": "limpieza"}, {"id": "velas-aceite", "title": "Ecological Candles from Used Cooking Oil", "category": "hogar", "tag": "Cleaning", "image": "assets/images/velas_aceite.webp", "views": 150000, "summary": "Learn how to recycle used kitchen oil to make clean-burning, long-lasting homemade scented candles using soy wax.", "intro": "Used cooking oil is one of the biggest contaminants in domestic water. By macerating and solidifying it with vegetable soy wax and organic cotton wicks, we can transform it into high-quality decorative aromatic candles, which do not produce black smoke and purify the domestic environment.", "healthBenefit": "By burning these vegetable candles you avoid inhaling hydrocarbons such as benzene and toluene, highly carcinogenic compounds emitted by commercial petroleum paraffin candles when they burn. This protects your internal respiratory health, keeps the air clean of volatile toxins, and reduces the development of petrochemical vapor headaches.", "time": "20 minutes", "rawDuration": "Filtered oil: 6 months", "finalDuration": "Finished candle: Years", "cost": "1.30 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Well filtered used cooking oil (150ml)", "price": "0.00 €"}, {"name": "Low melting soy wax (150g)", "price": "0.90 €"}, {"name": "Organic cotton wicks with metallic base", "price": "0.20 €"}, {"name": "Eucalyptus or cinnamon essential oil (15 drops)", "price": "0.15 €"}, {"name": "Small recycled glass jars", "price": "0.05 €"}], "steps": ["Filter the used cooking oil using a fine cotton cloth or coffee filter several times to remove any food residue or fried smell.", "Melt the soy wax in a bain-marie in a heatproof bowl until completely transparent.", "Remove from heat and slowly add the warm purified cooking oil to the melted soy wax, stirring gently to mix.", "Add 15 drops of your favorite essential oil to neutralize any residual odor and scent the candle.", "Place the cotton wick centered on the bottom of the recycled glass jar, holding the wick at the top with a toothpick or clothespin.", "Carefully pour the liquid wax and oil mixture into the glass jar.", "Let cool at room temperature for 4 hours until completely solidified to a creamy white color. Cut the wick to 1 cm and light."], "altUses": ["Mosquito-repellent outdoor candles by adding citronella essential oil.", "Emergency light points for self-contained electrical blackout kits.", "Rustic aromatic decorative detail for the home."], "extraInfo": "Vegetable soy wax has a low melting point and works as an excellent binder for liquid oils. By combining them at 50%, the wax absorbs the olive or sunflower oil and generates a slow and clean combustion. You burn natural wax without releasing soot or toxic carbon compounds associated with commercial paraffin.", "comparisonTable": [{"concepto": "Cost per Candle", "casero": "€0.65 (Per jar)", "comercial": "€6.00 ​​(Natural wax candle)", "diferencia": "Savings of 89.1%"}, {"concepto": "Wax Base", "casero": "Soy and recycled vegetable oil", "comercial": "Mineral paraffin (Petroleum derivative)", "diferencia": "No hydrocarbons"}, {"concepto": "Soot and Fumes", "casero": "Clean combustion without toxics", "comercial": "Benzene and black soot emission", "diferencia": "Clean home air"}, {"concepto": "Waste Impact", "casero": "Avoid contaminating 1000L of tap water", "comercial": "Generation of packaging and industrial waste", "diferencia": "Absolute ecological"}], "subcategory": "limpieza"}, {"id": "balsamo-calendula", "title": "Calendula and Olive Oil Repair Balm", "category": "cuerpo", "tag": "Remedies", "image": "assets/images/balsamo.webp", "views": 120000, "summary": "Traditional balsamic ointment formulated to relieve minor burns, skin irritations and extreme dryness using calendula flowers macerated in olive oil and beeswax.", "intro": "Calendula oleate has soothing, healing and anti-inflammatory properties thanks to its flavonoids and triterpenes. Combined with extra virgin olive oil and pure beeswax, this balm forms a breathable protective barrier on the skin that accelerates cell regeneration and deeply nourishes, without additives of mineral origin or petrolatum.", "healthBenefit": "It delivers lipid nutrients and essential vitamins directly to skin cells using pure plant oils, instead of coating the skin with petroleum-derived mineral oils (such as petroleum jelly or liquid paraffin). Hydrocarbon derivatives create a plastic waterproof film that clogs pores and prevents the skin from eliminating toxins naturally.", "time": "35 minutes (Previous maceration of 40 days)", "rawDuration": "Dried flowers: 2 years", "finalDuration": "Finished balm: 12 months", "cost": "3.20 €", "metrics": {"economy": 80, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Extra virgin olive oil (100ml)", "price": "0.80 €"}, {"name": "Dried organic calendula flowers (15g)", "price": "0.90 €"}, {"name": "Pure natural beeswax (15g)", "price": "1.20 €"}, {"name": "50ml amber glass jar", "price": "0.30 €"}], "steps": ["Preparation of the oleate: Place the dried calendula flowers in a clean glass jar. Cover them completely with the extra virgin olive oil. Close the jar and let it macerate in a warm, dry place away from direct sunlight for 40 days, shaking it gently each day.", "After 40 days, filter the oil using a clean cloth or fine cloth strainer, squeezing the flowers to extract all of the concentrated calendula extract.", "Pour the 100ml of the filtered oil into a heat-resistant glass container.", "Add the beeswax to the container.", "Place the container in a bain-marie over medium-low heat until the beeswax completely melts and mixes evenly with the olive oil.", "Remove from the heat and stir the mixture gently for a minute with a clean wooden spatula.", "Pour the liquid immediately into the 50ml amber glass jar before it begins to solidify.", "Let cool at room temperature uncovered for 3-4 hours until it reaches its final waxy consistency. Place the lid on tightly and store in a cool place."], "altUses": ["Baby diaper cream: its extreme softness protects against diaper rash without adding silicone or synthetic perfumes.", "Emergency nourishing lip balm for lips chapped by cold or wind.", "Intensive moisturizing cream for dry heels and elbows."], "extraInfo": "If you want to prepare the balm faster without waiting the 40 days, you can heat the dried flowers with the olive oil in a bain-marie over very low heat (without exceeding 50°C) for about 3 hours, stirring occasionally. This hot method extracts the active ingredients in an accelerated manner.", "comparisonTable": [{"concepto": "Cost per 50ml", "casero": "€1.60 (Per jar)", "comercial": "€12.50 (Pharmacy)", "diferencia": "Savings of 87.2%"}, {"concepto": "Formulation base", "casero": "Virgin olive oil", "comercial": "Vaseline / Petrolatum (Petroleum)", "diferencia": "100% Organic"}, {"concepto": "Allergens and Perfume", "casero": "No synthetic perfumes", "comercial": "Fragrance and PEG preservatives", "diferencia": "Hypoallergenic"}, {"concepto": "Light stability", "casero": "Protective amber glass", "comercial": "Generic plastic container", "diferencia": "Better conservation"}], "subcategory": "remedios"}, {"id": "pomada-llanten", "title": "Plantain Healing and Disinfecting Ointment", "category": "cuerpo", "tag": "Remedies", "image": "assets/images/pomada_llanten_nueva.webp", "views": 110000, "summary": "Natural antiseptic ointment made with fresh plantain leaves macerated in olive oil, ideal for curing eczema, chafing and minor cuts.", "intro": "The plantain (Plantago major) is one of the most valuable traditional medicinal plants for its content of aucubin (antiseptic), allantoin (skin regenerating) and silicic acid. This handmade ointment provides quick and safe relief for superficial wounds and irritations.", "healthBenefit": "It accelerates natural healing and disinfects the skin without the need for pharmaceutical creams with synthetic corticosteroids (which thin and weaken the structure of the epidermis) or petrolatum. As it does not contain artificial additives, it is perfectly safe for people with sensitive skin, allergies or dermatological reactivity.", "time": "35 minutes (Maceration: 20 days)", "rawDuration": "Dehydrated leaves: 1 year", "finalDuration": "Ointment in jar: 12 months", "cost": "1.80 €", "metrics": {"economy": 85, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Fresh harvested plantain leaves (50g)", "price": "0.00 €"}, {"name": "Extra virgin olive oil (100ml)", "price": "0.80 €"}, {"name": "Pure natural beeswax (15g)", "price": "0.90 €"}, {"name": "Small clean glass jar", "price": "0.10 €"}], "steps": ["Collect healthy plantain leaves. Wash them well and let them dry on a cloth for 24 hours to remove all moisture (water can ruin the ointment).", "Chop the dried leaves and place them in a glass jar. Cover them completely with the extra virgin olive oil.", "Let it marinate in the sun and shade for 20 days, or speed up the process by heating it in a bain-marie at 50°C for 3 hours over low heat.", "Filter the oil with a clean cotton cloth, squeezing the leaves to extract the chlorophyll and active plantain extract.", "Heat the filtered oil in a saucepan in a bain-marie and add the beeswax in pieces.", "Stir with a wooden spoon until the wax melts and integrates perfectly with the plantain oil.", "Immediately pour the mixture into the clean glass jar and let it cool, uncovered, until it solidifies."], "altUses": ["Soothing balm to relieve the itch of insect bites, mosquito bites or nettle burns.", "Protective and moisturizing treatment for hands severely chapped from working in the dirt.", "Relief from shoe scuffs on heels and feet."], "extraInfo": "The aucubin contained in the plantain has a powerful bactericidal effect. When combined with allantoin, it stimulates cell growth and skin renewal. It is one of the best natural alternatives to generic antibiotic ointments for daily use in the home medicine cabinet.", "comparisonTable": [{"concepto": "Cost per Jar (50ml)", "casero": "0.90 €", "comercial": "€9.50 (Commercial healing cream)", "diferencia": "Savings of 90.5%"}, {"concepto": "Hormonal Substances", "casero": "0% Corticosteroids or silicones", "comercial": "Frequent presence of parabens and petrolatum", "diferencia": "No altering chemicals"}, {"concepto": "Cell Regeneration", "casero": "Stimulated by natural allantoin", "comercial": "Synthetic based on artificial lipids", "diferencia": "Clean renovation"}, {"concepto": "Substrate Impact", "casero": "100% Biodegradable", "comercial": "Chemical drainage into water", "diferencia": "Ecological"}], "subcategory": "remedios"}, {"id": "champu-solid", "title": "Nettle and Rosemary Solid Shampoo", "category": "cuerpo", "tag": "Hygiene", "image": "assets/images/champu.webp", "views": 95000, "summary": "A biodegradable shampoo bar formulated to strengthen the hair follicle, regulate excess hair sebum and reactivate circulation thanks to green nettle and rosemary.", "intro": "The combination of green nettle (Urtica dioica) and rosemary (Salvia rosmarinus) provides minerals such as silicon and iron, as well as antioxidants. This shampoo bar cleans deeply without removing the natural oils from the scalp, avoiding the annoying 'rebound effect' of oil production caused by conventional sulfates. Being solid, it eliminates 100% of plastic packaging.", "healthBenefit": "Free your scalp from aggressive sulfates (SLS/SLES) and synthetic silicones that clog hair follicles and prevent perspiration and cellular respiration of the skin. By using clean ingredients, you regulate the natural production of hair sebum without causing dryness, flaking, dandruff or follicular weakening, promoting strong and healthy hair growth.", "time": "45 minutes", "rawDuration": "Dry raw material: 1 year", "finalDuration": "Shampoo tablet: 12 months", "cost": "2.20 €", "metrics": {"economy": 75, "health": 95, "ecosystem": 90}, "shoppingList": [{"name": "SCI natural surfactant (coconut) (70g)", "price": "1.40 €"}, {"name": "Dehydrated green nettle powder (10g)", "price": "0.30 €"}, {"name": "Extra virgin olive oil macerated with rosemary (10g)", "price": "0.20 €"}, {"name": "Concentrated infusion of wild rosemary (10ml)", "price": "0.05 €"}, {"name": "Pure rosemary essential oil (15 drops)", "price": "0.25 €"}], "steps": ["Put on a dust mask and mix the SCI surfactant and green nettle powder in a heat-resistant bowl.", "Add the olive oil macerated with rosemary and the concentrated rosemary infusion to the bowl.", "Place the bowl in a bain-marie over very low heat to soften the surfactants, stirring patiently with a wooden spatula for about 5-8 minutes until you obtain a dense and manageable paste.", "Remove from the heat and let it cool for a few minutes before adding the 15 drops of rosemary essential oil (excessive heat volatilizes the aroma and properties of the essential oil).", "Knead the mixture with your hands (you can use gloves) to finish integrating and press it firmly into a round or square silicone mold.", "Let the shampoo sit in the mold at room temperature for 24 hours to completely solidify.", "Unmold and let the tablet cure in a dry, ventilated place for another 48 hours before first use.", "Use: Moisten hair, rub the tablet directly on the scalp until foaming, massage and rinse with plenty of water."], "altUses": ["Gentle exfoliating body soap for oily or acne-prone skin.", "Beard washing tablet: rosemary acts as a disinfectant and facial hair conditioner."], "extraInfo": "To extend the life of your solid shampoo, always place it in a soap dish with water drainage after use. If kept dry between washes, a single 100g tablet can last between 70 and 80 washes, equivalent to almost 3 bottles of commercial liquid shampoo.", "comparisonTable": [{"concepto": "Cost per 100g", "casero": "2.20 €", "comercial": "€8.00 (Supermarket)", "diferencia": "Savings of 72.5%"}, {"concepto": "Preservatives/Parabens", "casero": "0% Natural", "comercial": "Methylparaben, Silicones", "diferencia": "Toxic-free"}, {"concepto": "Shelf life (Washed)", "casero": "Up to 80 washes", "comercial": "Approx. 30 per bottle", "diferencia": "Longer duration"}, {"concepto": "Carbon Footprint", "casero": "Null (No plastic or free water)", "comercial": "High (Transportation of water and packaging)", "diferencia": "Ecological"}], "subcategory": "higiene"}, {"id": "trampa-humedad", "title": "Natural Calcium Chloride Dehumidifier", "category": "tecnologia", "tag": "Heating", "image": "assets/images/trampa_humedad.webp", "views": 85000, "summary": "Learn how to make a quiet, natural moisture trap using calcium chloride salt and recycled containers to prevent mold.", "intro": "Calcium chloride is a saline compound with a very high hygroscopic capacity, which means that it actively absorbs water vapor from the air. This home dehumidifier captures excess moisture in closets or rooms in a 100% passive and silent way.", "healthBenefit": "Controls humidity in the home, preventing the appearance of household molds and fungal spores on the walls. Inhalation of mold spores is one of the main triggers of chronic rhinitis, airway congestion, headaches and bronchial asthma, especially in children and the elderly.", "time": "10 minutes", "rawDuration": "Materials: Unlimited", "finalDuration": "Active: 1 to 2 months (then replenish salt)", "cost": "0.90 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 95}, "shoppingList": [{"name": "Calcium Chloride Salt Flakes (250g)", "price": "0.60 €"}, {"name": "Recycled glass jar or container", "price": "0.05 €"}, {"name": "Fine mesh, cheesecloth or coffee filter", "price": "0.15 €"}, {"name": "Elastic band or piece of rope", "price": "0.10 €"}], "steps": ["Get a large glass jar and a plastic container that fits in its mouth (or use a small strainer placed over the jar).", "Place the coffee filter or fine cheesecloth in the bottom of the strainer or upper container.", "Pour the calcium chloride flakes into the gauze filter.", "Secure the cheesecloth with a rubber band or string so that the calcium chloride is suspended above the lower glass jar.", "Place the device in damp corners of the room, basements or closets.", "The compound will begin to absorb ambient moisture, gradually dissolving and dripping water in the form of liquid brine to the bottom of the glass jar.", "Monitor the jar every 3 weeks. Empty any accumulated water down the drain and add more calcium chloride flakes if necessary."], "altUses": ["Eliminator of musty odors inside clothing closets and shoe racks.", "Rust protector for metal tools in tool boxes.", "Control of condensation on motorhome or caravan windows during winter."], "extraInfo": "Calcium chloride (CaCl2) is a very hygroscopic salt that has chemical affinity with water molecules in the air. When it absorbs enough water, it undergoes a process called delictuescence, completely dissolving in the absorbed water. It does not consume any electricity, unlike compressor dehumidifiers.", "comparisonTable": [{"concepto": "Initial Cost", "casero": "0.90 €", "comercial": "€12.00 (Commercial anti-humidity device)", "diferencia": "Savings of 92.5%"}, {"concepto": "Electrical Consumption", "casero": "0W (Fully passive)", "comercial": "200W - 400W per hour", "diferencia": "Total savings"}, {"concepto": "Respiratory Health", "casero": "Prevents mold spores and asthma", "comercial": "Equivalent with HEPA filters", "diferencia": "Excellent prevention"}, {"concepto": "Acoustic Noise", "casero": "0 dB (Absolute silence)", "comercial": "35 dB (Continuous fan)", "diferencia": "Protect sleep"}], "subcategory": "calefaccion"}, {"id": "limpiador-citricos", "title": "Multipurpose Citrus and Vinegar Skin Cleaner", "category": "hogar", "tag": "Cleaning", "image": "assets/images/limpiador.webp", "views": 75000, "summary": "A homemade disinfectant cleaner and rinse aid made from macerating orange and lemon peels in white cleaning vinegar. Eliminates lime, grease and bad odors.", "intro": "White vinegar is known for its high concentration of acetic acid (around 8%), a powerful natural descaling and antibacterial agent. However, its pungent odor is sometimes annoying. By macerating citrus peels we release limonene and citrus essential oils from the skins, which neutralize the vinegar smell and provide additional degreasing and disinfectant properties.", "healthBenefit": "Protect your respiratory system and ocular mucous membranes by eliminating industrial chemical cleaners that release irritating gases based on ammonia, chlorine and volatile organic compounds (VOCs). Continued inhalation of these household vapors irritates the bronchi and lungs, being a direct risk factor for the development of asthma and multiple chemical sensitivity.", "time": "15 minutes (14 day maceration)", "rawDuration": "Fresh skins: 3 days", "finalDuration": "All-purpose cleaner: 12 months", "cost": "0.30 €", "metrics": {"economy": 98, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "White cleaning vinegar (1 Liter)", "price": "0.20 €"}, {"name": "Residue orange and lemon peels (4 units)", "price": "0.00 €"}, {"name": "Distilled filtered water (500ml)", "price": "0.05 €"}, {"name": "Reusable glass spray bottle", "price": "0.05 €"}], "steps": ["Wash the oranges and lemons well before peeling them to remove impurities. Save the peels resulting from regular consumption.", "Chop the citrus peels and place them in a large, wide-mouth glass jar until it is approximately half full.", "Pour the white cleaning vinegar over the citrus peels until they are completely covered. Close the jar tightly.", "Store the jar in a dark cupboard at room temperature for 14 days. The vinegar will change color to a light amber hue and absorb the citrus oils.", "After 14 days, filter the citrus vinegar with a fine strainer, discarding the peels (they can be thrown into the compost pile).", "To prepare the daily cleaner, mix 1 part concentrated citrus vinegar with 1 part distilled water (50% dilution) inside your glass spray bottle.", "Shake well before each use. Apply it directly to countertops, tiles, faucets, glass or toilets and clean with a microfiber or cotton cloth."], "altUses": ["Organic fabric softener: add 100ml of concentrated citrus vinegar (undiluted with water) to the fabric softener drawer in your washing machine. The clothes will come out soft and without the smell of vinegar.", "Lightweight Pipe Unclog: Add half a cup of baking soda down the drain and immediately pour a cup of this hot citrus vinegar. Let it sit and rinse with boiling water."], "extraInfo": "Usage Warning: Due to the natural acidity of the acetic acid in vinegar, avoid using this cleaner on delicate natural limestone surfaces such as polished marble or granite, as it may wear away the natural shine of the stone with continued use.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "0.15 €", "comercial": "€2.80 (Antiscale grease)", "diferencia": "Savings of 94.6%"}, {"concepto": "Inhaled toxicants", "casero": "Zero toxic gases", "comercial": "Ammonia, synthetic fragrances", "diferencia": "100% Healthy"}, {"concepto": "Effect on lime", "casero": "Very effective (Acetic acid)", "comercial": "Effective with strong chemicals", "diferencia": "Same effectiveness"}, {"concepto": "Environmental safety", "casero": "Biodegradable al 100%", "comercial": "Dangerous for aquatic fauna", "diferencia": "No contaminants"}], "subcategory": "limpieza"}, {"id": "desodorante-coco", "title": "Natural Baking Soda and Coconut Oil Deodorant", "category": "cuerpo", "tag": "Hygiene", "image": "assets/images/desodorante_coco.webp", "views": 380000, "summary": "Protect your armpits and eliminate bacteria with a gentle deodorant free of aluminum salts based on organic coconut oil and arrowroot starch.", "intro": "This homemade deodorant regulates odor effectively without blocking the biological process of perspiration. It uses coconut oil as a bactericidal agent and sodium bicarbonate to neutralize the acids produced by sweat, in a mild base of starch and tea tree essential oils.", "healthBenefit": "Completely dispenses with aluminum hydrochloride and commercial parabens. Aluminum physically blocks the sweat glands, preventing the natural expulsion of body toxins and accumulating in the axillary lymphatic tissues, which is linked to hormonal imbalances.", "time": "10 minutes", "rawDuration": "Coconut oil: 1 year", "finalDuration": "Deodorant: 6 months", "cost": "1.40 €", "metrics": {"economy": 88, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Extra virgin coconut oil (3 tablespoons)", "price": "0.60 €"}, {"name": "Baking soda (2 tablespoons)", "price": "0.10 €"}, {"name": "Cornstarch or arrowroot (2 tablespoons)", "price": "0.20 €"}, {"name": "Tea tree essential oil (10 drops)", "price": "0.50 €"}], "steps": ["If the coconut oil is solid, melt it in a gentle water bath until it is liquid.", "In a glass bowl, mix the baking soda and cornstarch until evenly combined.", "Add the tempered coconut oil little by little and stir with a wooden spoon until you obtain a smooth and uniform paste.", "Add the 10 drops of tea tree essential oil and mix well.", "Pour the paste into a small glass jar or clean, empty deodorant container.", "Let solidify in a cool place for 2 hours before using. Apply a small amount directly to the skin with your fingers."], "altUses": ["Soothing and sanitizing cream for feet prone to excessive sweating.", "Express purifying mask for rough cracked heels."], "extraInfo": "Corn starch absorbs excess moisture without clogging pores, while tea tree and coconut exert a broad-spectrum antibacterial and fungicidal effect, eradicating the Corynebacterium bacteria, which causes bad body odor.", "comparisonTable": [{"concepto": "Cost per 50g", "casero": "1.40 €", "comercial": "€6.50 (Commercial organic deodorant)", "diferencia": "Savings of 78.4%"}, {"concepto": "Aluminum Salts", "casero": "0% Without aluminum salts", "comercial": "Present in 90% of antiperspirants", "diferencia": "No harmful chemicals"}, {"concepto": "Pore ​​Clogging", "casero": "Allows you to breathe normally", "comercial": "Artificial sweat blocking", "diferencia": "Free dermal function"}, {"concepto": "Plastic Waste", "casero": "Refillable glass jar", "comercial": "Non-recyclable plastic packaging", "diferencia": "Zero Waste"}], "subcategory": "higiene"}, {"id": "colutorio-clavo", "title": "Antiseptic Clove and Cinnamon Mouthwash", "category": "cuerpo", "tag": "Hygiene", "image": "assets/images/colutorio_clavo.webp", "views": 310000, "summary": "Purifying mouthwash based on a concentrated decoction of cloves and cinnamon. Fresh breath, healthy gums and antibacterial protection.", "intro": "Cloves are rich in eugenol, which disinfects and protects gums. When combined with cinnamon, this homemade mouthwash gently fights bacteria. This rinse is the ideal complement to daily brushing with our <a href=\"pasta-dientes.html\">Clay Remineralizing Toothpaste</a>.", "healthBenefit": "Avoid the long-term use of industrial mouthwashes with alcohol, triclosan and chlorhexidine. Alcohol dries out the gums, facilitating the entry of toxins into the body and destroys all the beneficial bacteria in the mouth, which causes chronic bad breath and increases the risk of gingivitis.", "time": "15 minutes", "rawDuration": "Dried spices: 2 years", "finalDuration": "Prepared rinse: 3 weeks", "cost": "0.60 €", "metrics": {"economy": 92, "health": 98, "ecosystem": 100}, "shoppingList": [{"name": "Whole cloves (1 tablespoon)", "price": "0.20 €"}, {"name": "Ceylon cinnamon stick (1 pc)", "price": "0.25 €"}, {"name": "Purified tap water (500ml)", "price": "0.05 €"}, {"name": "Peppermint essential oil (5 drops)", "price": "0.10 €"}], "steps": ["Place the water in a saucepan and add the cloves and the chopped cinnamon stick.", "Bring to a boil over medium heat and cook for 10 minutes with the pot covered.", "Turn off the heat and let the infusion sit, covered, until it cools completely.", "Strain the liquid through a cloth or fine sieve to remove any residue from the spices.", "Add the 5 drops of peppermint essential oil to the strained liquid and stir vigorously.", "Pour the mouthwash into a clean glass bottle and store it in a cool place or in the refrigerator.", "Use: Rinse and gargle with 20ml of liquid after daily brushing."], "altUses": ["Travel mouth sanitizer spray in a small spray bottle.", "Gentle topical soothing lotion to relieve mild toothaches by applying with a cotton pad."], "extraInfo": "The eugenol contained in cloves temporarily blocks pain receptors in the gums, serving as an excellent emergency local analgesic in cases of swollen gums or acute tooth sensitivity.", "comparisonTable": [{"concepto": "Cost per 500ml", "casero": "0.60 €", "comercial": "€4.80 (Antiseptic mouthwash)", "diferencia": "Savings of 87.5%"}, {"concepto": "Alcohol in Formula", "casero": "0% Alcohol", "comercial": "Up to 20% Alcohol (burns the mucosa)", "diferencia": "Gingival protection"}, {"concepto": "Triclosan / Preservatives", "casero": "0% Synthetic chemicals", "comercial": "Present (suspected endocrine disruption)", "diferencia": "Health insurance"}, {"concepto": "Artificial flavor", "casero": "Mild natural spices", "comercial": "Synthetic sweeteners and colorants", "diferencia": "Natural"}], "subcategory": "higiene"}, {"id": "jarabe-tomillo", "title": "Natural Thyme and Honey Syrup for Cough", "category": "cuerpo", "tag": "Remedies", "image": "assets/images/jarabe_tomillo.webp", "views": 270000, "summary": "Grandmother's remedy to relieve cough, clear the bronchi and soothe an irritated throat with a concentrated infusion of wild thyme and pure honey.", "intro": "Thyme contains thymol and carvacrol, two volatile compounds with antispasmodic, expectorant and antiseptic properties. Combined with raw honey, this traditional syrup calms bronchial irritation and provides a soothing protective barrier in the throat.", "healthBenefit": "Avoid commercial chemical antitussive syrups formulated with dextromethorphan or codeine, which act at the level of the central nervous system by suppressing cough instead of helping to cough up mucus, in addition to containing artificial preservatives and high content of harmful refined sugars.", "time": "20 minutes", "rawDuration": "Dried thyme: 1 year", "finalDuration": "Syrup in refrigerator: 2 months", "cost": "1.80 €", "metrics": {"economy": 80, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Quality dried thyme (3 tablespoons)", "price": "0.40 €"}, {"name": "Raw artisanal bee honey (200g)", "price": "1.20 €"}, {"name": "Purified tap water (250ml)", "price": "0.05 €"}, {"name": "Juice of half a fresh lemon", "price": "0.15 €"}], "steps": ["Boil 250ml of water in a small saucepan.", "When it starts to boil, add the dried thyme, turn off the heat, cover the saucepan and let it infuse for 15 minutes.", "Filter the thyme infusion with a very fine strainer or cotton cloth, squeezing the leaves to extract all the juices.", "Pour the warm infusion into a clean glass jar and add the raw honey and lemon juice.", "Stir patiently with a wooden or plastic spoon until the honey is completely dissolved in the liquid.", "Close the jar tightly and store it in the refrigerator.", "Use: Take 1 tablespoon 3 to 4 times a day at the first symptoms of cough or cold."], "altUses": ["Medicinal sweetener for herbal teas when suffering from bronchial congestion.", "Gargle diluted with warm water to relieve tonsil pain or pharyngitis."], "extraInfo": "Pure raw honey acts as a natural demulcent, coating the irritated throat and reducing the cough reflex due to mechanical irritation, while lemon provides vitamin C that stimulates the body's immune defenses.", "comparisonTable": [{"concepto": "Cost per 250ml", "casero": "1.80 €", "comercial": "€9.50 (Antitussive syrup)", "diferencia": "Savings of 81%"}, {"concepto": "Cough Inhibitors", "casero": "natural expectorant (thymol)", "comercial": "Neuroactive chemicals (codeine)", "diferencia": "No side effects"}, {"concepto": "Artificial sweeteners", "casero": "raw bee honey", "comercial": "Refined glucose and sucrose syrup", "diferencia": "Healthy and nutritious"}, {"concepto": "Biodegradability", "casero": "100% Organic", "comercial": "Industrial chemical waste", "diferencia": "Ecological"}], "subcategory": "remedios"}, {"id": "mascarilla-arcilla", "title": "Green Clay and Tea Tree Purifying Mask", "category": "cuerpo", "tag": "Hygiene", "image": "assets/images/mascarilla_arcilla.webp", "views": 220000, "summary": "Purifying green bentonite clay and tea tree oil facial treatment. Absorbs toxins, regulates hair oil and hydrates without additives.", "intro": "Green clay is rich in minerals and has an extraordinary physical adsorption capacity, attracting impurities and oils from the pores like a magnet. With antibacterial tea tree oil, this mask is the ideal treatment to combat blackheads and revitalize tired skin.", "healthBenefit": "Avoid using commercial masks that contain parabens, microplastics and polyethylene glycol (PEG). These synthetic compounds clog pores, alter the lipid barrier and allow chemical toxins to pass into the bloodstream, dehydrating skin cells in the medium term.", "time": "15 minutes", "rawDuration": "Dry clay: Unlimited", "finalDuration": "Immediate use", "cost": "0.90 €", "metrics": {"economy": 88, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Purified Green Bentonite Clay (2 tablespoons)", "price": "0.40 €"}, {"name": "Distilled water or chamomile infusion (3 tablespoons)", "price": "0.10 €"}, {"name": "Pure Tea Tree Essential Oil (3 drops)", "price": "0.30 €"}, {"name": "Olive or sweet almond oil (half a teaspoon)", "price": "0.10 €"}], "steps": ["In a glass, wood or ceramic bowl (never metal), pour the 2 tablespoons of green clay.", "Add the distilled water or warm chamomile infusion little by little.", "Stir with a wooden spatula until you get a smooth, lump-free paste.", "Add the sweet almond oil and 3 drops of tea tree essential oil and mix.", "Clean your face with warm water and apply the mask with your fingers, avoiding the eye and lip area.", "Leave it on for 10 to 15 minutes. Don't let the clay dry completely (if it starts to crack, remove it first).", "Rinse with plenty of warm water, massaging in circular motions and dry with a clean towel."], "altUses": ["Disinfectant and soothing poultice for bee or wasp stings.", "Purifying treatment for oily scalp by applying it to the roots before washing."], "extraInfo": "The contact of wet green clay with the skin generates an ionic exchange: the clay absorbs positively charged ions (toxins and impurities) and releases essential minerals (silica, magnesium and calcium) that nourish and regenerate the outer layers of the dermis.", "comparisonTable": [{"concepto": "Cost per Application", "casero": "0.90 €", "comercial": "€4.50 (commercial single dose)", "diferencia": "Savings of 80%"}, {"concepto": "Microplastics/PEGs", "casero": "0% Synthetics (100% Mineral)", "comercial": "Frequently present as thickeners", "diferencia": "No plastic waste"}, {"concepto": "Chemical Preservatives", "casero": "Zero (Prepares instantly)", "comercial": "Parabens and phenoxyethanol", "diferencia": "Hypoallergenic"}, {"concepto": "Ionic action", "casero": "Natural and ionic active", "comercial": "Inert silicone-based", "diferencia": "real nutrition"}], "subcategory": "higiene"}, {"id": "aceite-hiperico", "title": "Macerated St. John's Wort Oil for Bumps and Burns", "category": "cuerpo", "tag": "Remedies", "image": "assets/images/aceite_hiperico.webp", "views": 195000, "summary": "The famous 'wound oil' or 'St. John's oil', made by macerating fresh St. John's wort flowers in olive oil in the sun to regenerate the skin.", "intro": "St. John's wort (Hypericum perforatum) contains hypericin and flavonoids with powerful healing, analgesic and anti-inflammatory effects. This oil with a characteristic ruby ​​red color is an essential traditional remedy for treating bruises, superficial burns and muscle pain.", "healthBenefit": "Replaces industrial anti-inflammatory ointments that contain synthetic active ingredients and synthetic preservatives. This vegetable oil delivers natural active ingredients directly to the skin cells, stimulating microcirculation and calming pain without overloading the liver with chemical toxins.", "time": "20 minutes (Maceration: 40 days in the sun)", "rawDuration": "Fresh flowers: 1 month", "finalDuration": "Macerated oil: 18 months", "cost": "1.50 €", "metrics": {"economy": 85, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Fresh St. John's Wort flowers (collected)", "price": "0.00 €"}, {"name": "Extra virgin olive oil (200ml)", "price": "1.30 €"}, {"name": "250ml clear glass jar", "price": "0.20 €"}], "steps": ["Collect the St. John's wort flowers at the end of June (traditionally in San Juan). Let them wilt for 24 hours to reduce the water content.", "Place the flowers into the transparent glass jar without pressing too much, until the jar is about three-quarters full.", "Cover the flowers completely with the extra virgin olive oil. Make sure no flowers are sticking out to avoid mold.", "Close the jar and let it macerate outdoors, in full sun, for 40 days (traditional method in the sun and calm). The oil will acquire a deep red color.", "Filter the oil through a fine cloth strainer, squeezing the flowers well to extract all the hypericin.", "Store the resulting red oil in an opaque (amber) glass jar in a cool, dark place.", "Use: Apply a few drops to the affected area with gentle massages (Note: it is photosensitive, do not expose yourself to direct sun after applying it)."], "altUses": ["Analgesic massage oil to soothe back pain, sciatica or low back pain.", "Night regenerating balm for extremely dry or peeling skin."], "extraInfo": "The plant's hypericin is soluble in lipids and oxidizes in the sun giving that characteristic ruby ​​red color. It is a powerful tissue regenerator that stimulates collagen synthesis, accelerating the healing of closed wounds and minor burns without leaving marked scars.", "comparisonTable": [{"concepto": "Cost per 100ml", "casero": "0.75 €", "comercial": "€15.00 (Herbalist / Pharmacy)", "diferencia": "Savings of 95%"}, {"concepto": "Formulation Matter", "casero": "100% virgin olive oil", "comercial": "Liquid paraffin and preservatives", "diferencia": "100% Organic"}, {"concepto": "Photosensitivity", "casero": "Natural (Avoid sun after applying)", "comercial": "Variable depending on artificial compounds", "diferencia": "Requires sun precaution"}, {"concepto": "Packaging Waste", "casero": "Reusable glass jar", "comercial": "Single-use plastic tube", "diferencia": "Zero Waste"}], "subcategory": "remedios"}, {"id": "crema-avena", "title": "Oatmeal and Aloe Vera Moisturizing Cream", "category": "cuerpo", "tag": "Hygiene", "image": "assets/images/crema_avena.webp", "views": 140000, "summary": "An ultra-gentle moisturizing lotion formulated for sensitive or atopic skin with colloidal oat mucilage, pure aloe vera gel and almond oil.", "intro": "This homemade cream combines the soothing and protective power of oats with the regenerative and moisturizing capacity of aloe vera. It does not contain synthetic perfumes, strong preservatives or petroleum-derived emulsifiers, making it ideal for babies and people with atopic dermatitis.", "healthBenefit": "Avoid daily contact with formaldehyde-releasing preservatives, artificial perfumes and parabens present in industrial creams. These chemical compounds penetrate the dermis, unbalance the skin's protective microbiome and can cause contact allergic outbreaks and dermal cell fatigue.", "time": "20 minutes", "rawDuration": "Dry ingredients: 1 year", "finalDuration": "Cream (keep cold): 1 month", "cost": "2.10 €", "metrics": {"economy": 82, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Organic rolled oats (2 tablespoons)", "price": "0.10 €"}, {"name": "Freshly extracted pure aloe vera gel (50ml)", "price": "0.50 €"}, {"name": "Pressed sweet almond oil (30ml)", "price": "1.20 €"}, {"name": "Distilled tap water (100ml)", "price": "0.05 €"}, {"name": "Pure beeswax for emulsifying (5g)", "price": "0.25 €"}], "steps": ["Boil the oats in 100ml of distilled water for 5 minutes to release the mucilage and starch. Strain the hot liquid (thick oat milk) through a cloth.", "In a heat-resistant container, place the almond oil and beeswax. Heat in a bain-marie until the wax melts.", "In another container, warm the strained oat milk and aloe vera gel.", "Slowly pour the water phase (oat milk and aloe) over the oil phase (oil and melted wax) while whisking vigorously with a small hand mixer.", "Continue whisking as the emulsion cools until you get a smooth, creamy consistency.", "Pour the resulting cream into a clean and previously sterilized glass jar.", "Let it cool completely in the refrigerator before closing and use it daily to soothe and hydrate the skin."], "altUses": ["Soothing body lotion for after shaving or skin waxing.", "Moisturizing night mask for dry or cold-damaged hands."], "extraInfo": "Colloidal oatmeal provides beta-glucans that form a moisturizing and protective film on the epidermis, relieving itching and reducing inflammation immediately. Aloe vera stimulates healing and regenerates deep dermal tissues.", "comparisonTable": [{"concepto": "Cost per 100ml", "casero": "1.40 €", "comercial": "€16.50 (Atopic skin cream)", "diferencia": "Savings of 91.5%"}, {"concepto": "Synthetic Fragrances", "casero": "0% Perfumes and allergens", "comercial": "Present (common cause of dermatitis)", "diferencia": "Hypoallergenic"}, {"concepto": "Chemical Preservatives", "casero": "Zero (Keeps in refrigerator)", "comercial": "Phenoxyethanol and parabens", "diferencia": "Clean ingredients"}, {"concepto": "Base Oils", "casero": "Natural almond oil", "comercial": "Paraffin and silicone mineral oil", "diferencia": "Lipid nutrition"}], "subcategory": "higiene"}, {"id": "tonico-quina", "title": "Rosemary and Quina Anti-Hair Loss Hair Tonic", "category": "cuerpo", "tag": "Remedies", "image": "assets/images/tonico_quina.webp", "views": 105000, "summary": "Traditional hair remedy formulated with cinchona bark and fresh rosemary leaves to strengthen hair and stimulate microcirculation.", "intro": "Cinchona (Cinchona bark) contains alkaloids that help strengthen the hair follicle, combating hair loss, while fresh rosemary provides antioxidants and stimulates blood flow to the scalp. This tonic is the natural alternative to maintain strong and dense hair.", "healthBenefit": "Avoid commercial lotions based on synthetic minoxidil or other chemical vasodilators that can cause itching, local skin irritations, hair dryness and hair dependence (immediate fallout effect when you stop using it), in addition to its cumulative toxicity.", "time": "25 minutes", "rawDuration": "Cinchona bark: 2 years", "finalDuration": "Prepared tonic: 2 months", "cost": "1.30 €", "metrics": {"economy": 85, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Crushed cinchona bark (20g)", "price": "0.60 €"}, {"name": "Fresh rosemary leaves (15g)", "price": "0.20 €"}, {"name": "Purified tap water (400ml)", "price": "0.05 €"}, {"name": "96 proof ethyl alcohol (50ml)", "price": "0.45 €"}], "steps": ["Place the cinchona bark in a saucepan with the 400ml of water and bring to the boil.", "Let the cinchona cook over low heat for 10 minutes with the saucepan covered to extract the alkaloids.", "Turn off the heat, add the fresh rosemary leaves to the saucepan and cover immediately to trap the volatile essences.", "Let the decoction sit until it is lukewarm (about 20 minutes) and filter it using a fine cotton cloth.", "Add 50ml of 96 proof alcohol to the strained liquid (it will act as a natural preservative and improve skin absorption).", "Pour the hair tonic into a bottle with a dispenser or sprayer.", "Use: Spray on dry or damp scalp with a gentle circular massage with your fingertips for 2 minutes. Do not rinse."], "altUses": ["Stimulating toning lotion to regulate excess oil in seborrheic scalps.", "Final hair shine rinse after regular washing."], "extraInfo": "Cinchona bark provides tannins and quinine, compounds that improve the keratin structure of the hair and activate the metabolism of the hair follicle, reducing the rate of hair loss during seasonal changes.", "comparisonTable": [{"concepto": "Cost per 450ml", "casero": "1.30 €", "comercial": "€18.00 (Anti-hair loss hair lotion)", "diferencia": "Savings of 92.7%"}, {"concepto": "Chemical Vasodilators", "casero": "0% Minoxidil or synthetics", "comercial": "Synthetic minoxidil for life", "diferencia": "No chemical dependency"}, {"concepto": "Synthetic Preservatives", "casero": "Zero preservatives (Preserved with alcohol)", "comercial": "Methylparaben and fragrances", "diferencia": "Pure ingredients"}, {"concepto": "Packaging Waste", "casero": "Reusable sprayer", "comercial": "Single-use plastic bottles", "diferencia": "Ecological"}], "subcategory": "remedios"}, {"id": "balsamo-labial", "title": "Cocoa Butter and Mint Lip Balm", "category": "cuerpo", "tag": "Hygiene", "image": "assets/images/balsamo_labial.webp", "views": 88000, "summary": "Handmade lip protector and moisturizer formulated with pure cocoa butter, almond oil and beeswax. Soft and fresh lips without Vaseline.", "intro": "This traditional grandmother's recipe nourishes and protects the delicate skin of the lips against the attacks of cold and wind. Cocoa butter provides healthy fats and antioxidants that repair cracks, while peppermint essential oil provides natural freshness and stimulates blood flow.", "healthBenefit": "Avoid commercial lip balms based on Vaseline or liquid paraffin (petrolatum). When applied to the lips, microquantities of petroleum mineral oils are involuntarily ingested, which accumulate in the spleen and liver over time as they are not metabolizable.", "time": "15 minutes", "rawDuration": "Butters and waxes: 18 months", "finalDuration": "Balm: 12 months", "cost": "0.95 €", "metrics": {"economy": 85, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Pure virgin cocoa butter (15g)", "price": "0.40 €"}, {"name": "Sweet almond oil (15ml)", "price": "0.20 €"}, {"name": "Pure grated beeswax (8g)", "price": "0.25 €"}, {"name": "Peppermint essential oil (4 drops)", "price": "0.10 €"}], "steps": ["In a small heat-resistant glass jar, place the cocoa butter, almond oil, and beeswax.", "Place the jar in a bain-marie over very low heat until all the ingredients have completely melted.", "Remove from the heat and quickly add the 4 drops of peppermint essential oil.", "Mix gently with a wooden stick to integrate the essential oil well.", "Immediately pour the molten liquid into small metal screw jars or 15ml glass jars.", "Let cool uncovered at room temperature for 2 hours until completely solidified into a creamy balm."], "altUses": ["Concentrated emergency moisturizer for dry cuticles on hands.", "Mild comforting ointment to apply to irritated nose after colds."], "extraInfo": "Cocoa butter is rich in polyphenols and vitamin E, powerful repair agents for epithelial tissue. Unlike mineral oils that plastically seal the skin, natural fats are absorbed and integrated into the cellular lipid barrier.", "comparisonTable": [{"concepto": "Cost per Unit (15ml)", "casero": "0.95 €", "comercial": "€3.80 (Commercial organic balm)", "diferencia": "Savings of 75%"}, {"concepto": "Hydrocarbon Intake", "casero": "0% Petrolatum (Total Security)", "comercial": "Common presence of petroleum oils", "diferencia": "100% Food Grade"}, {"concepto": "Hydration Duration", "casero": "Prolonged and nutritious", "comercial": "Creates dependency due to internal dehydration", "diferencia": "Real effectiveness"}, {"concepto": "Plastic Containers", "casero": "Reusable aluminum boxes", "comercial": "Single-use plastic applicators", "diferencia": "Zero Waste"}], "subcategory": "higiene"}, {"id": "infusion-valeriana", "title": "Relaxing Infusion of Valerian and Passionflower", "category": "cuerpo", "tag": "Remedies", "image": "assets/images/infusion_valeriana.webp", "views": 65000, "summary": "Preparation of medicinal herbs based on valerian root, passionflower and lemon balm to promote night rest and reduce stress naturally.", "intro": "This traditional mixture combines valerian (a natural sedative for the nervous system), passionflower (which prolongs deep sleep) and lemon balm (a pleasant flavor that relaxes the stomach). Ideal for alleviating insomnia and anxiety without resorting to synthetic drugs.", "healthBenefit": "Avoid regular use of benzodiazepines and pharmaceutical chemical sleeping pills. These medications generate rapid tolerance and chemical addiction, altering the natural physiological structure of sleep phases and causing drowsiness and decreased intellectual performance during the day.", "time": "10 minutes", "rawDuration": "Dried herbs: 2 years", "finalDuration": "Immediate use", "cost": "0.45 €", "metrics": {"economy": 90, "health": 100, "ecosystem": 100}, "shoppingList": [{"name": "Dried crushed valerian root (50g)", "price": "0.90 €"}, {"name": "Dried passionflower leaves (50g)", "price": "0.80 €"}, {"name": "Dried lemon balm leaves (50g)", "price": "0.60 €"}], "steps": ["In a large glass jar, mix the dry amounts of valerian, passionflower and lemon balm in equal parts. Shake the closed jar well to homogenize the mixture.", "To prepare a cup, heat 250ml of water until it is about to boil (about 90°C).", "Place a tablespoon of the herbal mixture in a tea infuser.", "Pour the hot water over the herbs and immediately cover the cup with a small plate to prevent the volatile oils from the lemon balm from evaporating.", "Let sit and infuse for 8 to 10 minutes.", "Remove the infuser, add a teaspoon of honey if you want to sweeten it and drink it hot half an hour before going to bed."], "altUses": ["Relaxing foot bath by adding a 1 liter concentrated infusion to the warm water of your feet.", "Mild diluted infusion to soothe stomach pain caused by nerves or stress."], "extraInfo": "The valerenic acids in valerian root act by inhibiting the destruction of the neurotransmitter GABA, facilitating a feeling of physical and mental relaxation that induces physiological sleep without causing residual morning drowsiness.", "comparisonTable": [{"concepto": "Cost per Cup", "casero": "0.15 €", "comercial": "€1.20 (Sleeping pills)", "diferencia": "Savings of 87.5%"}, {"concepto": "Addiction and Tolerance", "casero": "0% Risk of physical addiction", "comercial": "High risk and physical dependence", "diferencia": "Safe substance"}, {"concepto": "REM Sleep Quality", "casero": "Respect natural biological cycles", "comercial": "Reduces deep and REM sleep", "diferencia": "Restful rest"}, {"concepto": "Packaging Waste", "casero": "Compostable Bulk Herbs", "comercial": "Plastic blisters and cardboard boxes", "diferencia": "Zero Plastics"}], "subcategory": "remedios"}, {"id": "exfoliante-cafe", "title": "Coffee and Almond Oil Body Scrub", "category": "cuerpo", "tag": "Hygiene", "image": "assets/images/exfoliante_cafe.webp", "views": 45000, "summary": "Natural exfoliating treatment made with recycled coffee grounds and nourishing almond oil to reactivate circulation and soften the skin.", "intro": "This scrub takes advantage of the caffeine and texture of coffee grounds from your daily breakfast to remove dead skin cells. Mixed with almond oil and a few drops of essential orange, it deeply hydrates while stimulating lymphatic drainage in areas with cellulite.", "healthBenefit": "Avoid commercial exfoliants formulated with polyethylene microspheres (microplastics). These plastic compounds aggressively erode the dermis and are washed down the drain into rivers and oceans, where they enter the marine food chain and finally into our own body through food.", "time": "5 minutes", "rawDuration": "Recycled coffee: 3 days", "finalDuration": "Scrub in jar: 1 month", "cost": "0.50 €", "metrics": {"economy": 95, "health": 100, "ecosystem": 100}, "shoppingList": [{"name": "Dried breakfast coffee grounds (4 tablespoons)", "price": "0.00 €"}, {"name": "Sweet almond or virgin olive oil (3 tablespoons)", "price": "0.40 €"}, {"name": "Brown sugar (1 tablespoon)", "price": "0.05 €"}, {"name": "Sweet orange essential oil (5 drops)", "price": "0.05 €"}], "steps": ["Spread the breakfast coffee grounds on a plate and let them dry completely in the sun or in the open air so that they do not contain water.", "In a clean glass jar or bowl, mix the dry coffee grounds with the tablespoon of brown sugar.", "Add the sweet almond oil slowly and stir until the coffee powder is moist and well impregnated with oil.", "Add the 5 drops of sweet orange essential oil and mix.", "Close the jar tightly. Use it during the shower by applying a portion to your legs and buttocks.", "Perform gently ascending circular massages and rinse with plenty of warm water. You don't need to apply moisturizer afterwards."], "altUses": ["Hand scrub to remove motor grease stains or strong kitchen odors (garlic, onion).", "Nitrogen-rich fertilizer for pots after rinsing off the coffee in the shower."], "extraInfo": "Caffeine applied topically penetrates the superficial layers of the epidermis, stimulating circulation and improving peripheral blood flow, which helps tone tissues and reduce the orange peel appearance.", "comparisonTable": [{"concepto": "Cost per 100g", "casero": "0.35 €", "comercial": "€9.50 (Body scrub)", "diferencia": "Savings of 96.3%"}, {"concepto": "Plastic Microspheres", "casero": "0% Plastics (biodegradable waste)", "comercial": "Common synthetic polyethylene", "diferencia": "Respectful of the sea"}, {"concepto": "Base Oils", "casero": "Almonds / Virgin olive", "comercial": "paraffin mineral oil", "diferencia": "Dermal nutrition"}, {"concepto": "Caffeine Action", "casero": "Active and pure recycled coffee", "comercial": "Synthetic synthetic caffeine", "diferencia": "Useful recycling"}], "subcategory": "higiene"}, {"id": "pomada-arnica", "title": "Arnica Ointment for Muscle Pain", "category": "cuerpo", "tag": "Remedies", "image": "assets/images/pomada_llanten.webp", "views": 250000, "summary": "Anti-inflammatory ointment of arnica montana and pure beeswax, ideal for soothing joint pain, bruises and sprains.", "intro": "Arnica montana has components such as sesquiterpene lactones, which give it excellent analgesic and anti-inflammatory properties. This traditional ointment accelerates the resorption of bruises and reduces inflammation of stressed muscles naturally.", "healthBenefit": "Avoid synthetic chemical anti-inflammatory ointments (such as those based on diclofenac). These drugs penetrate through the skin and can burden the kidney and liver, in addition to drying out the epidermis and containing irritating petrochemical additives.", "time": "30 minutes", "rawDuration": "Dried arnica flowers: 2 years", "finalDuration": "Finished ointment: 12 months", "cost": "2.40 €", "metrics": {"economy": 80, "health": 100, "ecosystem": 95}, "shoppingList": [{"name": "Dried arnica montana flowers (20g)", "price": "0.90 €"}, {"name": "Extra virgin olive oil (100ml)", "price": "0.80 €"}, {"name": "Pure beekeeper's beeswax (15g)", "price": "0.60 €"}], "steps": ["Prepare the arnica oleate: place the dried flowers in a glass jar with the olive oil. Heat in a bain-marie over very low heat (without letting the water boil) for 2 hours to extract the active ingredients.", "Filter the hot oil using gauze or a clean cloth, squeezing the flowers well to extract all the essence.", "Pour the filtered oil back into the saucepan in a bain-marie.", "Add the chopped beeswax and stir continuously with a wooden spatula until completely melted.", "Remove from the heat and stir the mixture for 1 minute so that it begins to cool evenly.", "Pour the liquid into the glass jar and let it sit at room temperature until it solidifies into a firm ointment."], "altUses": ["Sports massage balm for before and after intense physical efforts.", "Comforting ointment to relieve mild joint pain due to changes in temperature."], "extraInfo": "The active substances in arnica montana act by stimulating local blood circulation in the capillaries, which favors the dispersion of fluids accumulated in bruises and prevents the formation of severe hematomas.", "comparisonTable": [{"concepto": "Cost per 50ml", "casero": "€1.20 (Per jar)", "comercial": "€12.90 (pharmacy sports ointment)", "diferencia": "Savings of 90.6%"}, {"concepto": "Anti-inflammatory Principles", "casero": "Natural Arnica Lactones", "comercial": "Diclofenac / Synthetic drugs", "diferencia": "Natural and safe"}, {"concepto": "Chemical Preservatives", "casero": "Zero additives (100% natural)", "comercial": "Parabens and synthetic preservatives", "diferencia": "Hypoallergenic"}, {"concepto": "Packaging Waste", "casero": "Reusable refillable jar", "comercial": "Non-recyclable metal-plastic tube", "diferencia": "Zero Waste"}], "subcategory": "remedios"}, {"id": "lavavajillas-mostaza", "title": "Dishwashing Liquid Mustard Powder and Vinegar", "category": "hogar", "tag": "Cleaning", "image": "assets/images/limpiador.webp", "views": 580000, "summary": "Traditional Russian method for washing greasy dishes by combining degreasing ground dry mustard, baking soda and white vinegar.", "intro": "Mustard powder is a powerful natural emulsifier that breaks down and absorbs animal and vegetable fat from dishes instantly. Combined with disinfectant vinegar, this dishwashing paste thoroughly cleans and shines glassware without leaving food odors or contaminating the water.", "healthBenefit": "Avoid using commercial dishwashers formulated with sodium lauryl sulfate and artificial colors. These detergents leave chemical microresidues on the surface of plates and glasses that we ingest in small doses with each meal, progressively altering the stomach mucosa and intestinal microbiome.", "time": "10 minutes", "rawDuration": "Powdered mustard: 1 year", "finalDuration": "Cleaning paste: 3 months", "cost": "0.75 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Ground dry mustard powder (50g)", "price": "0.40 €"}, {"name": "Baking soda (50g)", "price": "0.15 €"}, {"name": "White cleaning vinegar (50ml)", "price": "0.15 €"}, {"name": "Warm water (100ml)", "price": "0.05 €"}], "steps": ["In a wide-mouth glass jar, mix the mustard powder and baking soda.", "Add the white vinegar little by little (a natural effervescence will occur due to the alkaline-acid reaction).", "Pour in the warm water slowly while stirring with a wooden spoon.", "Mix vigorously until you achieve a fluid, creamy, yellowish paste.", "Use: Apply a teaspoon of this paste directly to the damp sponge.", "Scrub greasy dishes normally. The grease will melt away instantly. Rinse with warm water."], "altUses": ["Ecological degreasing cleaner for the surface of ovens and ceramic hobs.", "Polishing paste for tarnished stainless steel and copper pans."], "extraInfo": "Mustard seeds contain essential oils and enzymes that act by reducing the surface tension of fats, allowing them to mix with water and be easily removed by rinsing without the need for irritating synthetic foaming agents.", "comparisonTable": [{"concepto": "Cost per 250g", "casero": "0.75 €", "comercial": "€3.20 (Concentrated dishwasher)", "diferencia": "Savings of 76.5%"}, {"concepto": "Chemical Waste on Dishes", "casero": "0% Harmful residues (Edible)", "comercial": "Persistent petrochemical surfactants", "diferencia": "Digestive safety"}, {"concepto": "Effect on hands", "casero": "Soft, does not dry the dermis", "comercial": "Dermatitis due to strong sulfates", "diferencia": "Protect your hands"}, {"concepto": "Biodegradability", "casero": "100% Fast and harmless", "comercial": "Toxic to aquatic organisms", "diferencia": "Absolute ecological"}], "subcategory": "limpieza"}, {"id": "suavizante-vinagre", "title": "Vinegar and Baking Soda Fabric Softener", "category": "hogar", "tag": "Cleaning", "image": "assets/images/suavizante_vinagre.webp", "views": 520000, "summary": "Natural textile softener that removes lime from water, softens clothing fibers and prevents odors without leaving synthetic oils on fabrics.", "intro": "Commercial fabric softeners coat clothes with synthetic fats. This ecological vinegar-based softener neutralizes the hardness of lime and softens fabrics. It works perfectly if used together with <a href=\"detergent-ivy.html\">Ivy and Lavender Liquid Detergent</a> for a complete ecological wash.", "healthBenefit": "Avoid inhaling artificial fragrances and endocrine disruptors (such as phthalates) present in industrial fabric softeners. These compounds constantly evaporate from dry clothing, coming into contact with the respiratory tract and causing asthma and irritation in atopic skin.", "time": "10 minutes", "rawDuration": "White vinegar: 2 years", "finalDuration": "Softener: 6 months", "cost": "0.45 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "White cleaning vinegar (800ml)", "price": "0.20 €"}, {"name": "Purified water (200ml)", "price": "0.05 €"}, {"name": "Lavender essential oil (20 drops)", "price": "0.20 €"}], "steps": ["Get a large 1-liter glass or recycled plastic bottle.", "Pour the 200ml of purified water into the bottle.", "Add the 20 drops of essential oil to the water and shake vigorously to disperse the oil.", "Pour the 800ml of white vinegar into the bottle little by little.", "Close the bottle and shake it well before each wash to homogenize the mixture.", "Use: Add 50ml of this ecological fabric softener directly into the fabric softener compartment of your washing machine. The clothes will not smell like vinegar once dried, just clean."], "altUses": ["Anti-limescale cleaner for the washing machine by performing an empty hot wash cycle with 250ml.", "Antistatic spray for carpets diluted in spray water."], "extraInfo": "Vinegar dissolves calcium carbonate (lime) deposits in the wash water, which are directly responsible for making clothes stiff and rough when they dry. By removing this lime, the fibers regain their natural flexibility.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "0.45 €", "comercial": "€2.80 (Supermarket fabric softener)", "diferencia": "Savings of 83.9%"}, {"concepto": "Effect on Fibers", "casero": "Eliminates lime (breathable clothing)", "comercial": "Coats with petroleum grease (Waterproof)", "diferencia": "Breathable clothing"}, {"concepto": "Perfumes and Allergies", "casero": "Essential oil (Hypoallergenic)", "comercial": "Synthetic perfumes (risk of allergies)", "diferencia": "Baby safe"}, {"concepto": "Washing Machine Filters", "casero": "Cleans and descales pipes", "comercial": "Accumulates greasy sludge, clogging filters", "diferencia": "Extra maintenance"}], "subcategory": "limpieza"}, {"id": "insecticida-ortiga", "title": "Fermented Nettle Slurry (Insecticide and Fertilizer)", "category": "hogar", "tag": "Food", "image": "assets/images/insecticida_ortiga.webp", "views": 460000, "summary": "Learn how to make a fermented slurry from wild nettles, the best ecological preventive insecticide and defense activator for garden plants.", "intro": "Nettle slurry is a traditional agricultural recipe that provides large amounts of nitrogen and micronutrients to plants, while acting as a preventative against aphids, mites and fungi due to the organic compounds released during its anaerobic fermentation.", "healthBenefit": "Replaces commercial neonicotinoid chemical pesticides in your vegetables and fruit trees. These poisons penetrate the sap of the crops and are ingested directly when consuming your tomatoes or lettuce leaves, negatively affecting the kidney and immune health of the body.", "time": "15 minutes (Maceration: 10 days)", "rawDuration": "Fresh nettles: 1 day", "finalDuration": "Concentrated slurry: 6 months", "cost": "0.10 €", "metrics": {"economy": 98, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Fresh collected green nettle (1 kg)", "price": "0.00 €"}, {"name": "Rain or still water without chlorine (10 Liters)", "price": "0.10 €"}], "steps": ["Collect fresh nettles in spring or summer using thick gloves to avoid stinging yourself. Chop them lightly.", "Place the nettles in a large plastic bucket (never metal to avoid rust during fermentation).", "Pour the 10 liters of chlorine-free water over the chopped nettles.", "Cover the bucket with a breathable cloth to prevent insects from falling but allowing gas exchange.", "Place the bucket in the shade and stir the mixture for 5 minutes every day. Fermentation bubbles will begin to appear.", "When the bubbles stop rising (approx. 10 days, depending on the temperature), strain all the liquid with a fine cloth.", "Store the dark green liquid in dark bottles. Use: Dilute 10% in water for irrigation (fertilizer) or 5% to spray on the leaves (insecticide)."], "altUses": ["Homemade compost activator by pouring the undiluted slurry onto the organic compost pile.", "Fortifying irrigation lotion for young seedlings prone to root fungus."], "extraInfo": "During nettle fermentation, beneficial bacteria synthesize phytohormones that stimulate root and leaf growth of plants. The strong sulfurous smell of fermentation effectively repels olfactory insect pests.", "comparisonTable": [{"concepto": "Cost per 10 Liters", "casero": "0.10 €", "comercial": "€22.50 (Organic fertilizer and insecticide)", "diferencia": "Savings of 99.5%"}, {"concepto": "Residues in Vegetables", "casero": "Zero security deadlines (Harmless)", "comercial": "Security period of 10 to 20 days", "diferencia": "Immediate consumption"}, {"concepto": "Bee Health", "casero": "Does not affect pollinating insects", "comercial": "Kills bees and useful garden fauna", "diferencia": "Protect the ecosystem"}, {"concepto": "Nutritional Efficacy", "casero": "Excellent contribution of organic nitrogen", "comercial": "Artificial nitrogenous chemical fertilizers", "diferencia": "Liver soil"}], "subcategory": "alimentos"}, {"id": "limpiacristales-romero", "title": "Natural Rosemary Alcohol Glass Cleaner", "category": "hogar", "tag": "Cleaning", "image": "assets/images/limpiacristales_romero.webp", "views": 350000, "summary": "Get impeccable, glare-free glass, mirrors and windows with a fast-evaporating homemade cleaner based on isopropyl alcohol macerated with rosemary.", "intro": "Isopropyl alcohol is an organic solvent that dissolves grease and evaporates instantly without leaving marks on mirrors. Macerated with fresh rosemary, this homemade glass cleaner provides a pleasant wild aroma and long-lasting disinfectant properties.", "healthBenefit": "Avoid chemical window cleaning sprays that contain ammonia. Ammonia vapors are highly corrosive and irritate internal lung tissue and eyes, causing headaches and occupational asthma or chronic respiratory hypersensitivity.", "time": "10 minutes (Maceration: 7 days)", "rawDuration": "Fresh rosemary: 3 days", "finalDuration": "Cleaner: 12 months", "cost": "0.80 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 95}, "shoppingList": [{"name": "96 isopropyl or ethyl alcohol (250ml)", "price": "0.60 €"}, {"name": "Distilled or purified water (250ml)", "price": "0.05 €"}, {"name": "Fresh rosemary branches (2 pcs)", "price": "0.00 €"}, {"name": "White cleaning vinegar (1 tablespoon)", "price": "0.15 €"}], "steps": ["Place the fresh rosemary branches in a 500ml glass jar.", "Pour the 250ml of alcohol over the rosemary until it is covered. Close the jar and let it macerate for 7 days in a dark cupboard.", "Strain the alcohol (it will acquire a light greenish color and aroma of rosemary) removing the plant branches.", "Mix equal parts of the macerated rosemary alcohol and distilled water (250ml of each) in a spray bottle.", "Add the tablespoon of white vinegar to enhance the shine of the crystals.", "Shake gently before use. Spray on glass or mirrors and clean using crumpled newspaper or microfiber cloth."], "altUses": ["Multipurpose ecological disinfectant for phone and computer screens.", "Degreasing cleaner for chrome bathroom and kitchen faucets."], "extraInfo": "Alcohol breaks the surface tension of water and dissolves lipids (fingerprint grease) instantly. Due to its high volatility, it evaporates from the glass surface long before the water leaves marks or dry streaks.", "comparisonTable": [{"concepto": "Cost per 500ml", "casero": "0.80 €", "comercial": "€3.50 (Ammoniacal glass cleaner)", "diferencia": "Savings of 77.1%"}, {"concepto": "Ammonia / Vapors", "casero": "0% Ammonia (Rosemary smell)", "comercial": "High irritating ammonia content", "diferencia": "Aire interior sano"}, {"concepto": "Drying Trace", "casero": "Clean evaporation without marks", "comercial": "Equivalent", "diferencia": "Equal effectiveness"}, {"concepto": "Plastic containers", "casero": "Reused glass bottle", "comercial": "Single-use plastic container", "diferencia": "No plastics"}], "subcategory": "limpieza"}, {"id": "abono-platano", "title": "Banana and Coffee Skin Liquid Fertilizer", "category": "hogar", "tag": "Food", "image": "assets/images/abono_platano.webp", "views": 300000, "summary": "A homemade fertilizer rich in potassium and nitrogen formulated to enhance the flowering of your indoor and outdoor plants by reusing organic waste.", "intro": "Banana peels are one of the best natural sources of potassium (K), an essential mineral for the growth of flowers and fruits. Combined with the residual nitrogen and phosphorus from breakfast coffee, this organic liquid fertilizer nourishes your pots without harsh chemicals.", "healthBenefit": "Dispenses with commercial synthetic fertilizers based on synthetic chemical salts (industrial nitrates and phosphates). These salts alter the microbiological structure of the soil in the long term and are absorbed by your home garden plants, entering your kidneys through food.", "time": "15 minutes (Rest: 24 hours)", "rawDuration": "Fresh skins: 2 days", "finalDuration": "Diluted fertilizer: 1 week", "cost": "0.10 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Ripe banana skins (3 units)", "price": "0.00 €"}, {"name": "Used coffee grounds (2 tablespoons)", "price": "0.00 €"}, {"name": "Purified tap water (1.5 Liters)", "price": "0.05 €"}, {"name": "Organic waste sugar (1 tablespoon)", "price": "0.05 €"}], "steps": ["Cut the banana skins into small pieces about 2 cm on each side.", "Place the chopped skins and coffee grounds in a large pot with 1.5 liters of water.", "Bring to a boil over medium heat and simmer for 15 minutes. The water will turn brown.", "Turn off the heat, add the sugar (it will feed the soil microorganisms) and stir.", "Let the pot sit, covered, for 24 hours to ferment slightly and release the minerals.", "Strain the resulting liquid using a strainer, separating the banana remains (which you can compost).", "Use: Dilute the concentrated strained liquid 50% with regular irrigation water and water your plants once a week during flowering time."], "altUses": ["Foliar conditioner: dilute to 10% and apply as a spray to give shine and nutrients to the leaves.", "Direct food for worms in vermicomposting systems."], "extraInfo": "Potassium helps regulate the opening of stomata in plant leaves, which optimizes photosynthesis and cellular water use. Unlike chemicals, this fertilizer does not burn plant roots if accidentally overdosed.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "0.05 €", "comercial": "€6.80 (Liquid plant fertilizer)", "diferencia": "Savings of 99.2%"}, {"concepto": "Chemicals / Nitrates", "casero": "0% Synthetic salts", "comercial": "Artificial NPK (Salt buildup)", "diferencia": "healthy soil"}, {"concepto": "Soil Microorganisms", "casero": "Feeds and stimulates useful bacteria", "comercial": "Reduces and destroys microbial fauna", "diferencia": "Most fertile land"}, {"concepto": "Waste Use", "casero": "Take advantage of household waste", "comercial": "Generates single-use plastic containers", "diferencia": "Sustainable"}], "subcategory": "alimentos"}, {"id": "pastillas-wc", "title": "Toilet Disinfectant Effervescent Tablets", "category": "hogar", "tag": "Cleaning", "image": "assets/images/pastillas_wc.webp", "views": 240000, "summary": "Learn how to make your own effervescent tablets to clean, descale and aromatize the toilet in a 100% natural way using baking soda and citric acid.", "intro": "These homemade tablets clean the toilet by taking advantage of the acid reaction of citric acid and the alkalinity of sodium bicarbonate. When they come into contact with the toilet water, they release active oxygen bubbles that release dirt and accumulated lime without damaging the pipes.", "healthBenefit": "Replaces hanging chemical blocks and toilet bleaches. These commercial cleaners release continuous chlorine vapors into the bathroom that irritate your family's nasal passages, eyes, and lungs, in addition to containing contaminants that are difficult to break down.", "time": "15 minutes (Drying: 24 hours)", "rawDuration": "Dry ingredients: 1 year", "finalDuration": "Pills in a jar: 6 months", "cost": "1.10 €", "metrics": {"economy": 88, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Baking soda (200g)", "price": "0.50 €"}, {"name": "Citric acid powder (70g)", "price": "0.35 €"}, {"name": "Peppermint essential oil (25 drops)", "price": "0.20 €"}], "steps": ["In a large glass bowl, mix the baking soda and citric acid powder with a wooden spoon.", "Add the 25 drops of peppermint essential oil to the mixture and stir quickly to spread it.", "Spray water very lightly on the mixture (one or two sprays). Stir immediately to prevent effervescence from starting.", "The sweet spot is when the mixture has the texture of wet beach sand and compacts when pressed by hand.", "Press firmly into small silicone molds (for example, ice cube molds).", "Let the tablets dry in a dry, ventilated place for 24 hours until they completely solidify.", "Carefully unmold the pills and store them in a tightly closed glass jar. Use: Pour a tablet directly into the toilet, let the effervescence act for 15 minutes and wipe it with a brush."], "altUses": ["Descaling tablets to remove stubborn limescale from burnt vases or pots.", "Quick disinfectant cleaner for stainless steel kitchen sinks."], "extraInfo": "Baking soda deodorizes and has a mild bactericidal action, while citric acid very easily dissolves lime and yellowish urinary tartar deposits at the bottom of the bowl without corroding metal joints or pipes.", "comparisonTable": [{"concepto": "Cost per 15 Pills", "casero": "1.10 €", "comercial": "€4.90 (Industrial toilet blocks)", "diferencia": "Savings of 77.5%"}, {"concepto": "Chlorine/Bleach Fumes", "casero": "0% irritating chlorine", "comercial": "Continuous bleach fumes", "diferencia": "No lung risks"}, {"concepto": "Anti-limescale action", "casero": "Very effective natural citric acid", "comercial": "Strong corrosive acids", "diferencia": "Pipe insurance"}, {"concepto": "Biodegradability", "casero": "100% Immediate and natural", "comercial": "Highly harmful to river fauna", "diferencia": "Protect water"}], "subcategory": "limpieza"}, {"id": "fungicida-leche", "title": "Organic Milk and Baking Soda Fungicide", "category": "hogar", "tag": "Food", "image": "assets/images/fungicida_leche.webp", "views": 175000, "summary": "Fight powdery mildew, mildew and rust in your plants and garden with a natural fungicide based on cow's milk whey and sodium bicarbonate.", "intro": "This homemade fungicide uses the amino acids and mineral salts present in skimmed milk or whey to combat fungi on plants. Baking soda alters the pH of the leaf surface, preventing fungal spores from germinating.", "healthBenefit": "Avoid commercial chemical copper and sulfur fungicides in your urban garden. These metals and chemicals accumulate in the soil, killing useful worms, and enter the human body, where they can cause kidney toxicity and skin irritations.", "time": "10 minutes", "rawDuration": "Skimmed milk: 1 week", "finalDuration": "Immediate use", "cost": "0.35 €", "metrics": {"economy": 95, "health": 98, "ecosystem": 100}, "shoppingList": [{"name": "Skimmed cow's milk (200ml)", "price": "0.20 €"}, {"name": "Baking soda (10g)", "price": "0.10 €"}, {"name": "Purified tap water (800ml)", "price": "0.05 €"}], "steps": ["In a 1 liter spray bottle, add 800ml of chlorine-free water.", "Pour the 200ml of skimmed milk over the water (proportion 8 parts water to 2 parts milk).", "Add the teaspoon (10g) of baking soda to the bottle.", "Shake vigorously until the baking soda is completely dissolved in the milk solution.", "Spray the mixture directly on the infected leaves or as a preventive measure at dusk (never in full sun to avoid burning the leaves).", "Apply the mixture every 10 days, or every 4 days if the plant already has severe fungal symptoms."], "altUses": ["Lightweight nutrient conditioner for depleted potting soils.", "Spraying seeds before planting to prevent germination mold."], "extraInfo": "Milk contains whey and potassium phosphates, which have natural fungicidal properties when oxidized under indirect sunlight. In addition, it provides calcium to the leaves, strengthening their cell walls against future attacks.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "0.35 €", "comercial": "€11.50 (Systemic fungicide)", "diferencia": "Savings of 96.9%"}, {"concepto": "Soil Toxicity", "casero": "0% Heavy metals (Provides nutrients)", "comercial": "Accumulated copper destroys worms", "diferencia": "healthy soil"}, {"concepto": "Consumption Terms", "casero": "Instant vegetable consumption", "comercial": "Mandatory wait of 7 to 15 days", "diferencia": "quick garden"}, {"concepto": "Natural Formula", "casero": "Harmless milk and baking soda", "comercial": "Synthetic organophosphate compounds", "diferencia": "Ecological"}], "subcategory": "alimentos"}, {"id": "envolturas-cera", "title": "Ecological Beeswax Wraps", "category": "hogar", "tag": "Food", "image": "assets/images/envolturas_cera.webp", "views": 135000, "summary": "Reusable alternative to plastic wrap. Make your cotton fabric wrappers waterproofed with beeswax to preserve food.", "intro": "Beeswax wraps are natural cotton fabrics infused with wax and resin that act as a natural preservative for your snacks, cheeses and containers. They are breathable, self-adhesive and are easily washed to be reused hundreds of times.", "healthBenefit": "Avoid using PVC film and aluminum foil. The plastic film releases phthalates and bisphenols (BPA) on fatty foods (such as sausages or cheeses) with which it comes into direct contact, chemical compounds that act as powerful hormone disruptors in the body.", "time": "20 minutes", "rawDuration": "Cotton fabrics: Years", "finalDuration": "Finished wrap: 12 months (reusable)", "cost": "1.90 €", "metrics": {"economy": 85, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Scraps of 100% organic cotton fabric", "price": "0.60 €"}, {"name": "Pearls or pieces of pure beeswax (30g)", "price": "1.00 €"}, {"name": "Sweet almond oil (1 teaspoon)", "price": "0.15 €"}, {"name": "Baking or vegetable paper (2 sheets)", "price": "0.15 €"}], "steps": ["Cut the cotton fabric into squares or circles of different sizes (e.g. 20x20 cm and 30x30 cm). Grate the beeswax if it is blocky.", "Place a sheet of baking paper on your ironing board or a protected table.", "Place a piece of cotton fabric on the baking paper.", "Distribute the beeswax beads evenly over the entire surface of the fabric.", "Add a few drops of almond oil to the wax (it will provide flexibility so the wrapper doesn't crack when folded).", "Cover the cloth and wax with the second sheet of baking paper.", "Run a hot iron (medium temperature without steam) over the baking paper. The wax will melt and soak into the fibers of the fabric instantly. Remove the hot paper and let the fabric air dry for 2 minutes."], "altUses": ["Adjustable ecological lids for salad bowls or resting bread doughs.", "Natural folding case to carry cutlery or sandwiches on excursions."], "extraInfo": "Beeswax contains propolis and natural antimicrobial compounds that prevent the development of mold and bacteria in the wrapped foods, allowing them to breathe in a controlled manner without drying out.", "comparisonTable": [{"concepto": "Cost per 3 Wraps", "casero": "1.90 €", "comercial": "€15.00 (Bio commercials)", "diferencia": "Savings of 87.3%"}, {"concepto": "BPA/Phthalate Migration", "casero": "0% Plastics (100% Organic)", "comercial": "Migration of bisphenols from the films", "diferencia": "healthy foods"}, {"concepto": "Service Life", "casero": "Up to 1 year (Washable with cold water)", "comercial": "Single use (Aluminum foil/film)", "diferencia": "Reusable"}, {"concepto": "Impact on Landfills", "casero": "100% Compostable at the end of its life", "comercial": "Persistent plastic waste", "diferencia": "Zero Waste"}], "subcategory": "alimentos"}, {"id": "limpiamaderas-limon", "title": "Olive Oil and Lemon Wood Cleaner", "category": "hogar", "tag": "Cleaning", "image": "assets/images/limpiamaderas_limon.webp", "views": 90000, "summary": "Nourish, polish and protect your natural wood furniture with an ecological polish based on virgin olive oil and fresh lemon juice.", "intro": "Wood is an organic porous surface that dries out over time. Olive oil penetrates the pores of the wood, providing protective lipids, while the citric acid in lemon cleanses surface dirt and eliminates opacity.", "healthBenefit": "Avoid industrial spray wood polishes loaded with synthetic silicones, chemical solvents and volatile artificial perfumes. These petrochemical gases contaminate the air in your home and are inhaled directly, affecting the health of your bronchi.", "time": "5 minutes", "rawDuration": "Fresh ingredients: 1 week", "finalDuration": "Immediate use", "cost": "0.55 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Virgin olive oil (50ml)", "price": "0.35 €"}, {"name": "Strained fresh lemon juice (25ml)", "price": "0.15 €"}, {"name": "Lemon essential oil (5 drops)", "price": "0.05 €"}], "steps": ["Squeeze half a lemon and strain the juice through a fine strainer to remove any vegetable pulp that may rot.", "In a small jar or measuring bottle, mix the olive oil and strained lemon juice (proportion 2 parts oil to 1 part lemon).", "Add 5 drops of lemon essential oil to provide fresh and long-lasting fragrance.", "Shake the bottle vigorously before applying to temporarily mix the emulsion.", "Use: Apply a few drops of the emulsion to a soft cotton cloth.", "Rub the wood in the direction of the grain. Wipe with a second clean, dry cloth to remove any excess and bring out a spectacular satin shine."], "altUses": ["Protective conditioner for natural leather footwear and belts.", "Polishing cleaner for kitchen wooden cutting boards."], "extraInfo": "The lemon acts by disinfecting and sanitizing the wood and eliminating water stains, while the olive oil rehydrates the dry cellulose fibers, preventing them from cracking and forming a dust-repellent layer.", "comparisonTable": [{"concepto": "Cost per 100ml", "casero": "0.75 €", "comercial": "€4.50 (Silicone polish)", "diferencia": "Savings of 83.3%"}, {"concepto": "Silicone Layer", "casero": "Natural permeable nutrition", "comercial": "Creates a plastic layer that suffocates the wood", "diferencia": "Healthier wood"}, {"concepto": "Chemical Vapors", "casero": "0% Toxic (Pure lemon perfume)", "comercial": "Gas and hydrocarbon propellants", "diferencia": "Healthy air quality"}, {"concepto": "Gas Containers", "casero": "Reused glass jar", "comercial": "Pressurized aluminum aerosols", "diferencia": "No waste"}], "subcategory": "limpieza"}, {"id": "trampa-avispas", "title": "Vinegar and Sugar Trap for Wasps and Flies", "category": "hogar", "tag": "Food", "image": "assets/images/trampa_avispas.webp", "views": 70000, "summary": "Protect your outdoor meals with an eco-friendly and selective wasp and fly trap using cider vinegar and a recycled plastic bottle.", "intro": "This ecological trap takes advantage of the olfactory attraction that sweet cider vinegar exerts on flies and wasps. The inverted funnel design prevents trapped insects from escaping, keeping them away from your table without the need to use volatile chemical pesticides.", "healthBenefit": "Avoid using commercial spray insecticides based on pyrethroids and organophosphates for outdoors. These aerosols release poisonous particles that fall on food plates, glasses and people's skin, being compounds of high toxicity for liver and neurological health.", "time": "10 minutes", "rawDuration": "Plastic bottle: Reused", "finalDuration": "Active trap: 3 weeks (then renew liquid)", "cost": "0.40 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 95}, "shoppingList": [{"name": "Empty plastic bottle (1.5L or 2L)", "price": "0.00 €"}, {"name": "Apple cider vinegar (150ml)", "price": "0.20 €"}, {"name": "Common sugar (2 tablespoons)", "price": "0.10 €"}, {"name": "Organic liquid dish soap (3 drops)", "price": "0.10 €"}], "steps": ["Cut the top of the plastic bottle (about a third of its total height, right where it starts to widen).", "Pour the apple cider vinegar and 2 tablespoons of sugar into the bottom of the bottle.", "Add 3 drops of organic liquid soap (the soap breaks the surface tension of the liquid to prevent it from floating and taking off).", "Pour 100ml of water and stir with a stick to dissolve the sugar.", "Remove the cap from the top you cut and place it upside down, in a funnel shape, into the bottom of the bottle.", "Secure the two parts with tape or make two holes in the top edge to pass a rope through and hang it from a tree.", "Place the trap about 5 meters from your outdoor table. The wasps will enter, attracted by the acid-sweet smell and will not be able to get out."], "altUses": ["Trap fruit flies indoors by substituting beer for vinegar.", "Biological pest control in greenhouses by hanging traps at the foliage level."], "extraInfo": "Apple cider vinegar has a volatile acidity that is irresistible to flies and wasps, but actively repels bees. In this way, a selective trap is achieved, respecting the pollinating insects essential for the garden.", "comparisonTable": [{"concepto": "Cost per Trap", "casero": "0.40 €", "comercial": "€9.50 (Outdoor insect trap)", "diferencia": "Savings of 95.7%"}, {"concepto": "Vapors and Inhalation", "casero": "Zero volatile toxicants (Vinegar)", "comercial": "Chemical insecticide in suspension", "diferencia": "Clean outdoor air"}, {"concepto": "Ecological selectivity", "casero": "Protects bees (repels acidity)", "comercial": "Eliminates all insects indiscriminately", "diferencia": "Bee protection"}, {"concepto": "Waste Materials", "casero": "Reuse PET plastic bottles", "comercial": "Non-recyclable single-use plastic traps", "diferencia": "Eco-recycling"}], "subcategory": "alimentos"}, {"id": "ambientador-solido", "title": "Baking Soda and Essential Oil Air Freshener Blocks", "category": "hogar", "tag": "Cleaning", "image": "assets/images/ambientador_solido.webp", "views": 55000, "summary": "Deodorize closets, shoe cabinets and bathrooms with compact blocks scented with pure eucalyptus, lavender and lemon oils.", "intro": "Sodium bicarbonate has a great chemical capacity to absorb and neutralize alkaline and acid molecules that cause bad odors in the air. Blended with essential oils, this solid air freshener constantly deodorizes and purifies without electricity.", "healthBenefit": "Avoid commercial spray or plug-in air fresheners. They contain volatile organic compounds (VOCs) and formaldehydes that are potent respiratory irritants and chronic endocrine disruptors.", "time": "15 minutes (Drying: 24 hours)", "rawDuration": "Dry ingredients: 2 years", "finalDuration": "Active air freshener: 2 months", "cost": "0.85 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Baking soda (150g)", "price": "0.40 €"}, {"name": "Warm water (50ml)", "price": "0.05 €"}, {"name": "Essential oils (lavender and lemon) (30 drops)", "price": "0.40 €"}], "steps": ["Place the baking soda in a glass bowl.", "Add the 30 drops of essential oils directly to the baking soda.", "Pour in the warm water very slowly, tablespoon by tablespoon, stirring until you achieve a thick paste consistency.", "Pour the paste firmly into small silicone molds, pressing well.", "Let the blocks dry at room temperature for 24 to 48 hours until completely hardened.", "Unmold the tablets and place them in gauze bags or on small plates in the corners to be deodorized."], "altUses": ["Ecological deodorizing air freshener to place at the bottom of the trash can.", "Quick odor absorber in the refrigerator by placing a loose block in the door."], "extraInfo": "Instead of masking odors with strong chemical perfumes that saturate the olfactory receptors, baking soda chemically reacts with odorous gases (organic acids) neutralizing them at their roots.", "comparisonTable": [{"concepto": "Cost per 4 Units", "casero": "0.85 €", "comercial": "€6.80 (Plug air fresheners)", "diferencia": "Savings of 87.5%"}, {"concepto": "VOC emissions", "casero": "0% Synthetic Volatile Compounds", "comercial": "Continuous emission of phthalates and formaldehydes", "diferencia": "Toxic-free home"}, {"concepto": "Electrical Consumption", "casero": "0W Passive", "comercial": "Low consumption thermal plugs", "diferencia": "Energy savings"}, {"concepto": "Fill and Waste", "casero": "Fully compostable upon disposal", "comercial": "Replacement plastic containers", "diferencia": "Zero Plastics"}], "subcategory": "limpieza"}, {"id": "insecticida-jabon", "title": "Homemade Potassium Soap Insecticide", "category": "hogar", "tag": "Food", "image": "assets/images/insecticida_jabon.webp", "views": 35000, "summary": "Protect your plants from aphids, scale insects and whiteflies with a safe insecticidal spray based on diluted biodegradable potassium soap.", "intro": "Potassium soap softens the outer protective cuticle of soft-bodied insects, causing their natural dehydration without poisoning the garden. It is suitable for organic farming.", "healthBenefit": "Avoid fungicides and pesticides based on synthetic organophosphates. These persistent neurotoxicants accumulate in the vegetables you consume and damage neurological and liver balance.", "time": "10 minutes", "rawDuration": "Concentrated potassium soap: Years", "finalDuration": "Prepared solution: 1 month", "cost": "0.50 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Concentrated homemade soft potassium soap (20g)", "price": "0.15 €"}, {"name": "Purified tap water (1 Liter)", "price": "0.05 €"}, {"name": "96 proof ethyl alcohol (1 teaspoon)", "price": "0.30 €"}], "steps": ["Heat the water to lukewarm temperature (about 40°C) to help the soap dissolve.", "Pour the 20g of concentrated potassium soap into the warm water.", "Stir patiently until you achieve a homogeneous soapy mixture of yellowish-greenish color.", "Add the teaspoon of ethyl alcohol (acts as a penetrant to improve the contact action).", "Let the liquid cool completely and pour into your spray bottle.", "Use: Spray the plants at dusk, making sure to impregnate the upper and lower sides of all infected leaves."], "altUses": ["Mild disinfectant pot cleaner before planting new seeds.", "Emergency dishwasher diluted 10% in water."], "extraInfo": "As it is a mechanical insecticide that dissolves the cuticular fats of pests, insects cannot generate genetic resistance, unlike commercial synthetic chemical insecticides.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "0.50 €", "comercial": "€8.90 (Commercial potassium insecticide)", "diferencia": "Savings of 94.3%"}, {"concepto": "Pest Resistance", "casero": "0% Chance to resist (Physical)", "comercial": "Generates immune resistance of insects", "diferencia": "Always effective"}, {"concepto": "Security Deadlines", "casero": "0 Days (Wash vegetables and eat)", "comercial": "Mandatory wait of up to 15 days", "diferencia": "quick garden"}, {"concepto": "Soil Degradation", "casero": "Provides useful potassium for roots", "comercial": "It persists contaminating groundwater", "diferencia": "Nourish the soil"}], "subcategory": "alimentos"}, {"id": "friegasuelos-hierbas", "title": "Herbal Vinegar Floor Disinfectant", "category": "hogar", "tag": "Cleaning", "image": "assets/images/friegasuelos_hierbas.webp", "views": 15000, "summary": "Clean and disinfect tile and stoneware floors with a biodegradable cleaner macerated with antiseptic wild herbs such as thyme and eucalyptus.", "intro": "Cleaning vinegar is a great anti-limescale and natural degreaser. Macerating it with dried leaves of thyme, eucalyptus and lavender neutralizes the acidic aroma and releases disinfectant principles that keep the floors disinfected naturally.", "healthBenefit": "Avoid commercial floor cleaners chlorinated with bleach or ammonia. When mopping the floor with these compounds, heavy gases are released at floor level that damage the lungs and irritate the respiratory mucous membranes of your pets and small children.", "time": "15 minutes (Maceration: 14 days)", "rawDuration": "Dried herbs: 1 year", "finalDuration": "Cleaner: 12 months", "cost": "0.35 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Alcohol cleaning vinegar (1 Liter)", "price": "0.20 €"}, {"name": "Dried rosemary and eucalyptus leaves (30g)", "price": "0.10 €"}, {"name": "Eucalyptus essential oil (10 drops)", "price": "0.05 €"}], "steps": ["Place the dried herbs in a large glass jar.", "Pour the liter of white vinegar over the herbs and close the jar.", "Let the mixture marinate in a dark cupboard for 14 days so that the acidity absorbs the antiseptic oils.", "Filter the aromatic vinegar using a strainer, discarding any vegetable remains.", "Add the 10 drops of eucalyptus essential oil and shake well.", "Use: Add half a cup of this herbal vinegar to your dishwashing bucket with warm water. Mop the floors normally."], "altUses": ["Disinfectant countertop and toilet cleaner in a spray bottle.", "Carpet deodorizer by rubbing lightly with a cloth soaked in the dilution."], "extraInfo": "The acetic acid in vinegar dissolves dirt and shines tiles and stoneware, leaving the smell of vinegar fading within a few minutes of scrubbing and leaving behind a pleasant forest freshness.", "comparisonTable": [{"concepto": "Cost per Liter", "casero": "0.35 €", "comercial": "2.40 € (commercial Fregasuelos)", "diferencia": "Savings of 85.4%"}, {"concepto": "Gas at Ground Level", "casero": "Harmless vinegar and pine fumes", "comercial": "Irritant ammonia and chlorine residues", "diferencia": "Pet insurance"}, {"concepto": "Lime Removal", "casero": "Excellent descaler", "comercial": "Inert against hard lime deposits", "diferencia": "Brighter floors"}, {"concepto": "Plastic containers", "casero": "Refillable glass carafe", "comercial": "Single-use HDPE plastic container", "diferencia": "Eco-recycling"}], "subcategory": "limpieza"}, {"id": "horno-solar", "title": "Portable Cardboard Box Solar Oven", "category": "tecnologia", "tag": "Heating", "image": "assets/images/horno_solar.webp", "views": 550000, "summary": "Build an ecological oven that cooks food reaching 120°C using two cardboard boxes, aluminum foil and glass.", "intro": "The solar box oven is a passive cooking device based on the greenhouse effect and the concentration of solar radiation. It is an ecological emergency alternative ideal for cooking legumes, vegetables or bread without gas or electricity.", "healthBenefit": "Cook gently and at a constant low temperature (100°C-120°C). This better preserves the sensitive vitamins, enzymes and antioxidants of vegetables against frying at high temperatures that denature proteins and generate harmful compounds.", "time": "45 minutes", "rawDuration": "Cardboard boxes: Months", "finalDuration": "Oven operating: Years (if stored dry)", "cost": "4.50 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Two cardboard boxes (different sizes)", "price": "0.00 €"}, {"name": "Household aluminum foil (1 roll)", "price": "1.50 €"}, {"name": "Glass or methacrylate sheet (30x40cm)", "price": "2.50 €"}, {"name": "Old newspapers and white glue", "price": "0.50 €"}], "steps": ["Completely line the inside of the small box and the inside of the large box with aluminum foil, gluing it well with white glue.", "Place old crumpled newspapers in the bottom of the large box to act as thermal insulation.", "Place the small box centered inside the large box, filling all the surrounding free space with more compacted newspaper.", "Paint the bottom of the small box matte black using black cardboard or ecological water-based paint.", "Build a fitted cardboard lid for the outer box, cutting out a center window to match the size of the small box.", "Glue the glass sheet into the gap in the central window of the lid, sealing the joints.", "Build a folding cardboard tab lined with aluminum on the lid to serve as a solar reflector. Place your containers in the bottom of the oven, cover it and point it towards the sun."], "altUses": ["Emergency water pasteurizer keeping water canisters at 70°C for 1 hour.", "Dryer for wet legumes or cereals on sunny days."], "extraInfo": "Visible solar radiation passes through the glass and heats the black bottom of the oven, transforming into long-wave infrared radiation. Since glass is opaque to this infrared radiation, the heat is trapped inside, cooking the food slowly.", "comparisonTable": [{"concepto": "Gas/Light Consumption", "casero": "0W (Passive solar energy)", "comercial": "2000W (Conventional electric oven)", "diferencia": "100% savings"}, {"concepto": "Frying Toxins", "casero": "0% Acrylamide compounds", "comercial": "High in fried and industrial roasts", "diferencia": "healthy cooking"}, {"concepto": "Fire danger", "casero": "Very low (No flames or electricity)", "comercial": "Danger of electrical overheating", "diferencia": "Insurance"}, {"concepto": "Waste Materials", "casero": "Recycled materials (Cardboard and newspaper)", "comercial": "Industrial metal furnaces", "diferencia": "Biodegradable"}], "subcategory": "calefaccion"}, {"id": "bomba-ariete", "title": "PVC Manual Water Pump (Ram Pump)", "category": "tecnologia", "tag": "Agua", "image": "assets/images/bomba_ariete.webp", "views": 490000, "summary": "Build a PVC hydraulic pump that lifts water meters high without electricity or fuel, taking advantage of water hammer.", "intro": "The ram pump is a traditional invention that uses the kinetic energy of moving water in an inclined pipe to lift a fraction of that water to high altitudes. It works 100% autonomously and continuously without external energy sources.", "healthBenefit": "It ensures a constant supply of clean water in orchards or isolated farms, promoting self-cultivation and personal hygiene in a completely passive way. Its silent operation, free of gasoline engines, reduces pollution.", "time": "1 hour", "rawDuration": "PVC pipes: Years", "finalDuration": "Bomb active: Decades (requires cleaning)", "cost": "15.00 €", "metrics": {"economy": 90, "health": 90, "ecosystem": 100}, "shoppingList": [{"name": "1 inch PVC tees and pressure elbows", "price": "3.50 €"}, {"name": "Bronze Swing Check Valves (2 pcs)", "price": "7.50 €"}, {"name": "Thick soda plastic bottle", "price": "0.00 €"}, {"name": "PVC glue and Teflon tape", "price": "4.00 €"}], "steps": ["Assemble the 1-inch PVC pipes into a T, placing the water inlet at one end.", "Install the first check valve facing downward on a branch of the tee. This valve should be open by default.", "Install the second check valve facing upward toward the plastic bottle that will serve as the pressure chamber.", "Attach the plastic bottle upside down over the valve to serve as a compressed air accumulator lung.", "Connect the outlet hose to the rear branch of the tee.", "Connect the water inlet pipe to a tank or river located at least 1 meter above the pump.", "Start the system by manually pressing the shock valve several times until the automatic heartbeat cycle begins."], "altUses": ["Elevator of accumulated rainwater to elevated tanks for irrigation.", "Pond aerator and rustic aquaculture thanks to continuous flow."], "extraInfo": "Water hammer is a pressure wave that occurs when a rapidly moving column of water comes to an abrupt stop. When the shock valve closes, the pressure rises so much that it opens the second valve, injecting water into the compressed air chamber.", "comparisonTable": [{"concepto": "Gasoline/Electricity Expense", "casero": "0W (Passive hydraulic pressure)", "comercial": "600W per hour (Motorpump / Electropump)", "diferencia": "100% savings"}, {"concepto": "Continuous Operation", "casero": "24 hours a day, 365 days", "comercial": "Requires human ignition and control", "diferencia": "Autonomous"}, {"concepto": "Technical Maintenance", "casero": "Very low (Clean sand from joints)", "comercial": "Common (Oil filters and spark plugs)", "diferencia": "long life"}, {"concepto": "Smoke Emission", "casero": "0% Emissions (No engine noise)", "comercial": "CO2 and gas emissions", "diferencia": "Eco-responsible"}], "subcategory": "agua"}, {"id": "calentador-manguera", "title": "Solar Water Heater with Black Hose", "category": "tecnologia", "tag": "Heating", "image": "assets/images/calentador_manguera.webp", "views": 400000, "summary": "Build a thermophonic system to heat water for domestic use or an outdoor shower using a black spiral polyethylene hose.", "intro": "The solar hose heater takes advantage of the high capacity of black polyethylene plastic to absorb solar radiation and transfer that heat to the water retained inside. It is an ideal passive heater for outdoor showers or rustic campsites.", "healthBenefit": "Ensures hygienic hot water for daily cleaning, reducing exposure to internal combustion gases (butane, propane) present in poorly ventilated commercial gas heaters.", "time": "30 minutes", "rawDuration": "Polyethylene hose: Years", "finalDuration": "Active installation: Years", "cost": "10.50 €", "metrics": {"economy": 90, "health": 90, "ecosystem": 100}, "shoppingList": [{"name": "20mm black polyethylene hose (50m)", "price": "8.50 €"}, {"name": "Plastic cable ties and hose connectors", "price": "2.00 €"}], "steps": ["Roll the 50 meters of black hose into a flat spiral or snail shape on a rigid base.", "Secure the spiral with zip ties to keep the hose rings tightly together.", "Paint the base matte black to maximize heat absorption.", "Place the solar thermal panel facing south on a flat spot with maximum sun exposure.", "Connect one end of the hose to the cold water inlet.", "Install a stopcock at the hot water outlet end.", "Let the water sit in the hose exposed to the sun for 45 minutes. The water will easily reach optimal temperatures."], "altUses": ["Ecological auxiliary heater for small garden pools.", "Water tempering system for irrigation of delicate seedbeds."], "extraInfo": "Black polyethylene absorbs visible solar radiation and converts it into heat. Being compactly coiled, the hose minimizes heat loss to the wind.", "comparisonTable": [{"concepto": "Gas/Light Consumption", "casero": "0W (Passive solar thermal)", "comercial": "1500W (Electric heater / Thermos)", "diferencia": "100% savings"}, {"concepto": "Gas Fume Risk", "casero": "0% Combustion gases (Monoxide)", "comercial": "Risk of leaks and poisoning", "diferencia": "Family safety"}, {"concepto": "Purchase Cost", "casero": "10.50 €", "comercial": "€120.00 (Water heater)", "diferencia": "Savings of 91.2%"}, {"concepto": "Environmental Footprint", "casero": "Zero emissions in use", "comercial": "Generates CO2 in each combustion", "diferencia": "100% Sustainable"}], "subcategory": "calefaccion"}, {"id": "trampa-condensacion", "title": "Solar Condensation Trap for Irrigation Water", "category": "tecnologia", "tag": "Food", "image": "assets/images/trampa_condensacion.webp", "views": 340000, "summary": "Ultra-localized passive solar distillation and irrigation system for plants and crops, reducing water consumption by half through condensation.", "intro": "This solar distillation irrigation system produces pure evaporated water from sea or brackish water, or simply from moist soil. It works by trapping solar water vapor which then drips steadily to the plant's roots.", "healthBenefit": "It allows you to water domestic vegetables with natural distilled water free of salts, chlorine and microscopic impurities that accumulate in edible plants, providing healthier food.", "time": "15 minutes", "rawDuration": "Plastic bottles: Reused", "finalDuration": "Trap active: Years (requires recharges)", "cost": "0.10 €", "metrics": {"economy": 95, "health": 90, "ecosystem": 100}, "shoppingList": [{"name": "5L large soda plastic bottle", "price": "0.00 €"}, {"name": "1.5L small plastic bottle", "price": "0.00 €"}], "steps": ["Cut the base of the small 1.5L bottle and keep the bottom to serve as a glass.", "Cut the base of the large 5L bottle and keep the screw-on cap.", "Make a small hole in the ground next to the plant and insert the internal water glass, filling it with water.", "Cover the inner glass with the protective outer hood of the large 5L bottle, setting it firmly in the ground.", "Cover the edges of the outer bottle with soil to seal tightly.", "Solar radiation will evaporate the water from the inner glass, which will hit the cold walls of the outer bell, falling in the form of fine distillate."], "altUses": ["Survival distiller to obtain fresh water from brackish water.", "Passive holiday irrigation system for pots on sunny terraces."], "extraInfo": "This process mimics the planet's hydrological cycle on a microscopic scale. By not consuming any energy and being airtight, it prevents water loss through direct evaporation to the dry air of the garden.", "comparisonTable": [{"concepto": "Irrigation Water Consumption", "casero": "Savings from 50% to 80% (No losses)", "comercial": "Traditional irrigation with evaporation losses", "diferencia": "Great water savings"}, {"concepto": "Chlorine/Salt Contribution", "casero": "0% Lime and salts (Pure distilled water)", "comercial": "Salt and chlorine supply from the tap", "diferencia": "healthy plants"}, {"concepto": "Installation Cost", "casero": "€0.05 (Recycled materials)", "comercial": "Expensive drip systems", "diferencia": "Economic"}, {"concepto": "Plastic Waste", "casero": "Reuse PET plastic bottles", "comercial": "Single-use plastic hoses", "diferencia": "Sustainable"}], "subcategory": "alimentos"}, {"id": "huerto-vertical", "title": "Vertical Garden with Plastic Bottles", "category": "tecnologia", "tag": "Food", "image": "assets/images/huerto_vertical.webp", "views": 280000, "summary": "Optimize urban space by growing aromatic plants, lettuce and strawberries in a modular vertical structure made with reused plastic bottles.", "intro": "The vertical garden is an ideal solution for terraces, balconies or sunny walls with limited space. Using PET plastic bottles linked in a cascade, a gravity irrigation system is generated where the excess water from one bottle irrigates the one below.", "healthBenefit": "Make it easy to grow your own organic, pesticide-free foods at home. Consuming freshly harvested vegetables guarantees the maximum contribution of vitamins and live enzymes.", "time": "40 minutes", "rawDuration": "Plastic bottles: Reused", "finalDuration": "Active structure: Years", "cost": "2.50 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Empty 2L PET plastic bottles (6 units)", "price": "0.00 €"}, {"name": "Strong rope or clothesline wire (3m)", "price": "1.20 €"}, {"name": "Earth or organic substrate rich in humus", "price": "1.30 €"}], "steps": ["Clean the 6 plastic bottles well and screw the caps firmly on.", "Cut out a 12x8 cm rectangular window on one side of each bottle.", "Make two holes aligned at the top and bottom of each bottle to pass the tie ropes through.", "Poke several small holes in the cap of each bottle to allow slow drainage of water.", "Pass the ropes or wires through the side holes of the bottles, linking them one below the other in a vertical cascade. Secure with knots.", "Fill the inside of each bottle with enriched organic substrate.", "Plant your lettuce, strawberry or aromatic sprouts in the windows. Hang the structure on your sunny wall."], "altUses": ["Ornamental vertical garden of wildflowers to decorate facades.", "Cuttings rooting system with localized irrigation."], "extraInfo": "This vertical modular design reduces water evaporation thanks to the fact that the substrate is semi-covered by the plastic structure of the bottle, protecting the roots from frost.", "comparisonTable": [{"concepto": "Cost for 6 Modules", "casero": "2.50 €", "comercial": "€39.00 (Growing table / Vertical)", "diferencia": "Savings of 93.5%"}, {"concepto": "Nutritional Quality", "casero": "Freshly harvested organic vegetables", "comercial": "Transported and refrigerated vegetables", "diferencia": "Greater plant vitality"}, {"concepto": "Space Use", "casero": "Excellent on small walls", "comercial": "Requires space on flat ground", "diferencia": "Ideal urban"}, {"concepto": "Plastic Footprint", "casero": "Avoid and reuse plastic waste", "comercial": "Commercial Virgin Plastic Pots", "diferencia": "Eco-recycling"}], "subcategory": "alimentos"}, {"id": "biodigestor-casero", "title": "Homemade Methane Gas Generator (Biodigester)", "category": "tecnologia", "tag": "Food", "image": "assets/images/biodigestor_casero.webp", "views": 230000, "summary": "Learn how to build a small-scale anaerobic biodigester to produce ecological methane gas (biogas) from organic waste.", "intro": "The biodigester is an airtight container where anaerobic bacteria decompose food remains and organic matter in the absence of oxygen, producing biogas and an excellent concentrated liquid fertilizer (biol).", "healthBenefit": "Generates cooking fuel in a clean way, reducing the cost of butane gas cylinders. In addition, it reduces bad sanitary odors and the proliferation of insects by treating garbage airtight.", "time": "1 hour", "rawDuration": "Plastic drum: Years", "finalDuration": "Active biodigester: Years (requires feeding)", "cost": "18.00 €", "metrics": {"economy": 88, "health": 90, "ecosystem": 100}, "shoppingList": [{"name": "Large plastic drum with airtight lid (50L)", "price": "10.00 €"}, {"name": "PVC pipe and gas valves", "price": "4.50 €"}, {"name": "Flexible hose and sealing silicone", "price": "3.50 €"}], "steps": ["Make a hole in the lid of the plastic drum to connect the gas outlet. Seal the joint with silicone.", "Install the gas shut-off valve to the outlet PVC pipe.", "Make a hole at mid-height in the side of the drum to introduce the organic remains through an inclined tube.", "Make a third hole in the bottom of the drum to drain any excess liquid fertilizer.", "Fill the biodigester two-thirds full with a mixture of fresh manure, organic waste and warm water.", "Close the container tightly and let it rest at a warm temperature to activate the fermentation.", "The gas generated will begin to inflate a storage bag connected by the hose, ready for use."], "altUses": ["Production of concentrated premium biological liquid fertilizer for pots.", "Clean anaerobic treatment of garden waste and dry leaves."], "extraInfo": "Anaerobic digestion occurs in four phases: hydrolysis, acidogenesis, acetogenesis and methanogenesis. Methanogenic bacteria convert fatty acids into methane and carbon dioxide.", "comparisonTable": [{"concepto": "Fuel Expense", "casero": "€0 (Own gas production)", "comercial": "€16.50 (Commercial butane cylinder)", "diferencia": "100% savings"}, {"concepto": "Garbage Treatment", "casero": "Clean, odor-free on-site treatment", "comercial": "Landfills with unhealthy leachate", "diferencia": "Zero waste"}, {"concepto": "Resulting fertilizer (Biol)", "casero": "Gift premium organic fertilizer", "comercial": "Requires purchasing commercial subscriptions", "diferencia": "Extra fertility"}, {"concepto": "Carbon Footprint", "casero": "Reduces direct methane emissions", "comercial": "Net fossil fuel emissions", "diferencia": "Carbon neutrality"}], "subcategory": "alimentos"}, {"id": "prensa-briquetas", "title": "Fuel Briquette Paper Press", "category": "tecnologia", "tag": "Heating", "image": "assets/images/prensa_briquetas.webp", "views": 185000, "summary": "Recycle newspapers, old cardboard and sawdust to make compact, high-density, long-lasting briquettes for your fireplace or stove.", "intro": "Paper and sawdust briquettes are an ecological and free alternative for home heating. Made by wet pressing, they accumulate great thermal inertia, burning slowly without generating excessive smoke.", "healthBenefit": "Avoid using commercial paraffin lighting tablets, which release highly carcinogenic vapors when ignited. These briquettes burn cleanly and harmlessly.", "time": "30 minutes (Drying: 1 week in the sun)", "rawDuration": "Metal/wood press: Years", "finalDuration": "Dry briquettes: Unlimited", "cost": "1.00 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Pallet wood tubes and slats", "price": "0.00 €"}, {"name": "Metal rod and long screws", "price": "1.00 €"}], "steps": ["Cut old cardboard and newspapers into small pieces.", "Place the chopped paper in a bucket of warm water and let it soak for 24 hours.", "Grind the wet mixture until you get a paper-thin pulp.", "Add 30% clean wood sawdust to paper pulp. Mix well.", "Build a cylindrical wooden mold with multiple small holes in the side walls.", "Put the wet pulp into the mold.", "Apply pressure with a manual lever press. The water will come out through the holes, compacting the briquette. Unmold and let dry in the sun."], "altUses": ["Rustic emergency fuel for outdoor cooking.", "Mosquito repellent briquettes by adding dry eucalyptus leaves to the mixture."], "extraInfo": "The cellulose contained in recycled paper acts as a powerful natural glue when it dries, binding the sawdust particles together without the need for highly toxic chemical resins.", "comparisonTable": [{"concepto": "Winter Cost", "casero": "€0 (Free fuel)", "comercial": "€95.00 (Bags of firewood and charcoal)", "diferencia": "100% savings"}, {"concepto": "Smoke and Ash", "casero": "Slow burning, compostable ash", "comercial": "Smoke with industrial resins (depending on firewood)", "diferencia": "Clean combustion"}, {"concepto": "Wood Savings", "casero": "Save trees by recycling cardboard", "comercial": "Comes from commercial forest logging", "diferencia": "Absolute ecological"}, {"concepto": "Ignition Time", "casero": "Burns for 2 to 3 constant hours", "comercial": "Fast combustion of softwood", "diferencia": "Long lasting"}], "subcategory": "calefaccion"}, {"id": "filtro-biochar", "title": "Biochar Filter for Soil Purification", "category": "tecnologia", "tag": "Agua", "image": "assets/images/filtro_biochar.webp", "views": 160000, "summary": "Learn how to produce pyrolyzed charcoal (Biochar) to filter toxins, fix carbon and improve the fertility of agricultural soils.", "intro": "Biochar is a highly porous charcoal produced by pyrolysis (combustion in the absence of oxygen) of plant remains. This system helps retain nutrients, and perfectly complements the purifier of our <a href=\"filtro-agua.html\">Carbon and Sand Water Filter</a> at home.", "healthBenefit": "Filters and adsorbs heavy metals and synthetic pesticide residues in your garden soil, preventing these chemical toxins from being absorbed by the roots of your vegetables.", "time": "1 hour", "rawDuration": "Pruning remains: €0.00", "finalDuration": "Effect on soil: Hundreds of years (fixes permanent carbon)", "cost": "0.50 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Coarse pruning remains of clean wood", "price": "0.00 €"}, {"name": "Two metal drums (one large 50L and another 20L)", "price": "0.00 €"}, {"name": "Purified tap water", "price": "0.50 €"}], "steps": ["Place the dry pieces of wood into the small 20L drum.", "Close the small container with its lid tightly.", "Place the small drum inside the large metal drum.", "Fill the space between both drums with common firewood to start a fire and light the outer chamber.", "Light the outside fire and keep it burning vigorously for 2 hours.", "When it cools, open the small container to obtain the porous Biochar charcoal.", "Use: Crush the charcoal, mix it with moist compost for 2 weeks and incorporate it into the soil in your pots."], "altUses": ["Deodorizing and odor purifying filter for chicken coops.", "Additive for water retention in seedbed substrates."], "extraInfo": "Biochar has a specific surface area of ​​up to 400 m² per gram. This gives it an enormous ionic capacity to adsorb nutrient cations, preventing them from being lost to rainwater.", "comparisonTable": [{"concepto": "Cost per 10 kg", "casero": "0.00 € (Autofabricado)", "comercial": "€28.50 (packaged commercial biochar)", "diferencia": "100% savings"}, {"concepto": "Carbon Sequestration", "casero": "Permanently fixes CO2 (Centuries)", "comercial": "Equivalent", "diferencia": "Change mitigation"}, {"concepto": "Nutrient Retention", "casero": "Excellent thanks to high porosity", "comercial": "Soluble fertilizers that are lost with water", "diferencia": "Fertilizer savings"}, {"concepto": "Substrate of Life", "casero": "Stable microbial refuge", "comercial": "Commercial sterilized inert soil", "diferencia": "living earth"}], "subcategory": "agua"}, {"id": "lampara-alcohol", "title": "Alcohol and Rope Emergency Lamp", "category": "tecnologia", "tag": "Heating", "image": "assets/images/lampara_alcohol.webp", "views": 125000, "summary": "Build a constant light lamp using a recycled glass jar, 96 proof sanitary alcohol, and a cotton rope wick.", "intro": "Alcohol lamps provide clean, long-lasting lighting without greasy fumes. They use ethyl alcohol as a fast-burning fuel through capillary action using an organic cotton wick, making it an irreplaceable emergency lighting tool.", "healthBenefit": "Avoid kerosene lamps or commercial petroleum-derived paraffin candles. These lamps release toxic gases and black soot that saturate the air inside the home.", "time": "10 minutes", "rawDuration": "Glass Jar: Reused", "finalDuration": "Fuel per hour: 15ml", "cost": "0.60 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 95}, "shoppingList": [{"name": "Small glass jar with metal lid", "price": "0.05 €"}, {"name": "100% natural cotton rope (wick)", "price": "0.10 €"}, {"name": "Sanitary alcohol of 96 or 70 degrees (100ml)", "price": "0.40 €"}, {"name": "Screw and metal washers", "price": "0.05 €"}], "steps": ["Make a clean 5mm hole in the center of the metal lid of the glass jar.", "Insert the hollow metal screw into the hole in the cover, securing it with washers.", "Cut a piece of cotton rope that is about 5cm longer than the height of the jar.", "Pass the cotton rope through the small metal tube of the lid, so that it protrudes about 5mm.", "Fill the glass jar with sanitary alcohol halfway.", "Close the lid by screwing it on tightly, letting the string absorb the alcohol.", "Light the wick at the top. The flame will be constant and bluish."], "altUses": ["Homemade rustic laboratory Bunsen burner for heating liquids.", "Emergency light for outdoor terraces by adding repellent oils."], "extraInfo": "The combustion of ethyl alcohol produces only carbon dioxide and water vapor in minimal proportions, without releasing unburned carbon particles (soot).", "comparisonTable": [{"concepto": "Cost per 4 Hours", "casero": "0.25 €", "comercial": "€2.80 (Batteries for commercial flashlight)", "diferencia": "Savings of 91%"}, {"concepto": "Soot Generation", "casero": "0% Soot (Blue clean flame)", "comercial": "High soot in paraffin and oil candles", "diferencia": "clean air"}, {"concepto": "Waste Batteries", "casero": "Zero polluting chemical batteries", "comercial": "Non-recyclable alkaline batteries", "diferencia": "Sustainable"}, {"concepto": "Filling Ease", "casero": "Easy and safe (Common alcohol)", "comercial": "Hard to find flammable kerosene", "diferencia": "Practical"}], "subcategory": "calefaccion"}, {"id": "estufa-rocket", "title": "'Rocket' Emergency Can Stove", "category": "tecnologia", "tag": "Heating", "image": "assets/images/estufa_rocket.webp", "views": 98000, "summary": "Build a highly thermally efficient stove that boils water in minutes using three metal cans and insulating ash.", "intro": "The Rocket Stove is an outdoor-optimized internal combustion design that burns twigs with great physical efficiency. To heat indoor rooms safely and without smoke, we recommend our <a href=\"candle-stove.html\">Pot and Candle Stove</a>.", "healthBenefit": "Avoid inhaling fumes from traditional open fires when cooking outdoors. The Rocket design directs the air flow and burns wood gases before they escape, reducing emissions by 80%.", "time": "30 minutes", "rawDuration": "Metal cans: Reused", "finalDuration": "Stove operational: Months (then renew cans)", "cost": "0.50 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "Large 1kg metal can", "price": "0.00 €"}, {"name": "Soda cans or medium preserves (2 units)", "price": "0.00 €"}, {"name": "Wood ash or fine sand (insulator)", "price": "0.00 €"}], "steps": ["Clean the three cans well and remove the lids.", "Make a side circular hole near the base of the large can.", "Cut the first medium can to act as a horizontal firewood feed elbow.", "Insert the horizontal tube of the medium can through the hole in the large can.", "Place the second medium can vertically on the inside elbow to create the L-shaped internal chimney.", "Fill all the surrounding hollow space with dry wood ash or fine sand.", "Make a small horizontal feed grate and light the fire at the base of the vertical chimney."], "altUses": ["Outdoor emergency heater for cold camps.", "Quick survival cooker to boil water from streams."], "extraInfo": "Ash insulation keeps the internal chimney at over 600°C. This temperature causes the volatile gases in the wood to burn in the upper area of ​​the chimney.", "comparisonTable": [{"concepto": "Fuel Consumption", "casero": "Very low (Few dry twigs)", "comercial": "Requires butane gas or chemical tablets", "diferencia": "Free fuel"}, {"concepto": "Smoke Emission", "casero": "Reduced by 80% (Burn the smoke)", "comercial": "High in traditional open fires", "diferencia": "clean smoke"}, {"concepto": "Material Cost", "casero": "€0.50 (Can recycling)", "comercial": "€45.00 (Portable camping stove)", "diferencia": "Savings of 98.8%"}, {"concepto": "Burn Risk", "casero": "Tempered insulated exterior walls", "comercial": "Hot exposed metal walls", "diferencia": "Insurance"}], "subcategory": "calefaccion"}, {"id": "nevera-arena", "title": "Desert Sand Refrigerator without Electricity", "category": "tecnologia", "tag": "Food", "image": "assets/images/nevera.webp", "views": 78000, "summary": "Variant of the Zeer refrigerator optimized for storing water and dairy bottles using a terracotta vessel and moist siliceous sand.", "intro": "This rustic evaporative cooler uses the same physical principles as traditional clay jugs. By wetting the siliceous sand contained in the intermediate chamber of two vessels, a constant lateral evaporation is induced.", "healthBenefit": "It keeps your drinks cool gradually without reaching extreme temperatures that irritate the throat and cause pharyngitis. In addition, by not using electricity, it avoids electromagnetism.", "time": "20 minutes", "rawDuration": "Clay pots: Unlimited", "finalDuration": "Sand water refill: 12 hours", "cost": "7.50 €", "metrics": {"economy": 90, "health": 90, "ecosystem": 95}, "shoppingList": [{"name": "Unglazed terracotta pots (2 units)", "price": "6.00 €"}, {"name": "River sand or clean fine sand and cork", "price": "1.50 €"}], "steps": ["Seal the bottom holes of the pots with natural corks.", "Pour a 4cm layer of fine sand into the largest pot.", "Place the small pot in the center of the large pot.", "Fill the circular space between both pots with river sand.", "Moisten the sand slowly with cold water until it is thoroughly soaked.", "Place the water or milk bottles inside the small inner pot.", "Cover the top with a damp cotton cloth and place it in a ventilated corner."], "altUses": ["Ecological cooler for the garden porch or terrace in summer.", "Preservative for delicate freshly picked fruits."], "extraInfo": "Unglazed clay is permeable to water vapor. Ambient heat energy accelerates the evaporation of water from the side sand, cooling the interior chamber.", "comparisonTable": [{"concepto": "Electricity Expense", "casero": "0W (Natural thermodynamics)", "comercial": "120W (Minibar / Electric nevera)", "diferencia": "100% savings"}, {"concepto": "Conservation Humidity", "casero": "Ideal average humidity for dairy products", "comercial": "Dries and dehydrates liquids", "diferencia": "Nature conservation"}, {"concepto": "Noises at Rest", "casero": "0 dB (Absolute silence)", "comercial": "40 dB (minibar compressor)", "diferencia": "No noise pollution"}, {"concepto": "Materials Used", "casero": "Terracotta and sand (Natural)", "comercial": "Injected plastic and insulating foams", "diferencia": "100% Ecological"}], "subcategory": "alimentos"}, {"id": "riego-solar", "title": "Solar Drip Irrigation System", "category": "tecnologia", "tag": "Food", "image": "assets/images/trampa_condensacion.webp", "views": 50000, "summary": "Learn how to make a passive solar drip irrigation system using plastic bottles, reducing water evaporation from the soil by half.", "intro": "Passive solar irrigation is a highly effective urban and rural agricultural technique. It uses the sun's energy to evaporate water contained in a tank, condensing it on a plastic cover that drips directly onto the ground.", "healthBenefit": "Promotes ecological self-cultivation by allowing precision irrigation of your medicinal vegetables. Prevents water stress on the roots and reduces fungi.", "time": "10 minutes", "rawDuration": "Plastic bottles: Reused", "finalDuration": "Active irrigation: Months (then refill water from the tank)", "cost": "0.10 €", "metrics": {"economy": 95, "health": 95, "ecosystem": 100}, "shoppingList": [{"name": "5L clear plastic bottle (bell)", "price": "0.00 €"}, {"name": "1.5L small plastic bottle (reservoir)", "price": "0.00 €"}], "steps": ["Cut the small 1.5L bottle in half and keep the bottom to serve as a water glass.", "Cut the base of the large 5L bottle and keep the screw-on cap.", "Place the glass of the small bottle with water right on the ground next to the plant.", "Cover the glass with the bell of the large 5L bottle, digging it into the ground a little.", "The sun will heat the air inside the bell by evaporating the water. The steam will condense on the walls, falling in the form of a fine distillate to the floor."], "altUses": ["Automatic weekend irrigation for planters and pots on terraces.", "Localized humidification system for potted shrubs."], "extraInfo": "This system self-regulates irrigation according to the sun: the greater the solar radiation, the greater the evaporation and condensation there will be, providing more water to the plant just when the soil is drier.", "comparisonTable": [{"concepto": "Water Consumed", "casero": "Savings of up to 80% (No losses)", "comercial": "30% loss due to soil evaporation", "diferencia": "Great water savings"}, {"concepto": "Automatic Irrigation", "casero": "Self-regulated by solar intensity", "comercial": "Requires timers and batteries", "diferencia": "100% Passive"}, {"concepto": "Cost per Plant", "casero": "€0.05 (Recycled bottles)", "comercial": "€6.50 (Commercial drippers)", "diferencia": "Absolute savings"}, {"concepto": "Water Quality", "casero": "Pure distilled water without chlorine", "comercial": "Chlorinated water that stresses roots", "diferencia": "Plant health"}], "subcategory": "alimentos"}, {"id": "unguento-cera-oliva", "title": "Beeswax and Olive Oil Repair Ointment", "category": "cuerpo", "subcategory": "remedios", "tag": "Remedies", "image": "assets/images/unguento_cera_oliva.webp", "views": 340000, "summary": "Basic lipid formulation to regenerate areas of extreme dryness and cracks using only melted operculum wax and extra virgin olive oil.", "intro": "This traditional ointment is one of the oldest and most effective protective ointments that exist. The combination of beeswax and extra virgin olive oil creates a natural occlusive barrier that seals in skin moisture, stimulating cell regeneration in cracked elbows, heels and hands without resorting to artificial paraffins.", "healthBenefit": "Isolates the epidermis from moisture loss without clogging pores, avoiding paraffins and mineral oils derived from petroleum present in commercial Vaselines. This prevents chronic irritations and allows the skin to breathe while absorbing the antioxidants from the extra virgin olive oil.", "time": "20 minutes", "rawDuration": "Stable ingredients: 12 months", "finalDuration": "Finished ointment: 12 months", "cost": "0.90 €", "metrics": {"economy": 85, "health": 90, "ecosystem": 95}, "shoppingList": [{"name": "Operculum virgin beeswax", "price": "1.20 € (50g)"}, {"name": "Extra virgin olive oil", "price": "1.50 € (200ml)"}, {"name": "Wide Mouth Sterilized Glass Jar", "price": "0.00 € (reciclado)"}], "steps": ["Weigh 50g of virgin beeswax from the operculum and place it in a heat-resistant container.", "Add 200ml of extra virgin olive oil to the container along with the wax.", "Place the container in a bain-marie over low heat, stirring constantly with a wooden spoon or clean spatula until the wax melts completely and mixes homogeneously with the oil.", "Remove from heat just as it melts to avoid overheating the olive oil.", "Pour the still hot liquid mixture into the sterilized glass jar carefully.", "Let it cool at room temperature without covering the jar until it solidifies completely (it will acquire a pale yellow color and creamy texture).", "Once cool, cover tightly and store in a cool, dark place."], "altUses": ["Protective and softening balm for pet pads.", "Natural protective wax to nourish and polish small utensils or wood finishes.", "Emergency lip balm for extreme cold conditions."], "extraInfo": "Beeswax contains fatty esters, free acids and long chain compounds that give it emollient and film-forming properties. When mixed with olive oil, rich in oleic acid and vitamin E, an anhydrous emulsion is generated (without water) that does not require any type of artificial preservatives.", "comparisonTable": [{"concepto": "Unit ribs (250g)", "casero": "2.70 €", "comercial": "€12.00 (Pharmacy Vaseline)", "diferencia": "Savings of 77.5%"}, {"concepto": "Synthetic ingredients", "casero": "0% (100% natural y biodegradable)", "comercial": "100% Paraffin / Petrolatum", "diferencia": "Toxin free"}, {"concepto": "Nutritive capacity", "casero": "High (fatty acids and vitamin E)", "comercial": "Null (merely physical block)", "diferencia": "Nourishes the skin"}]}, {"id": "quitamanchas-percarbonato", "title": "Solid Active Oxygen Stain Remover (Percarbonate)", "category": "hogar", "subcategory": "limpieza", "tag": "Cleaning", "image": "assets/images/quitamanchas_percarbonato.webp", "views": 410000, "summary": "Powdered textile bleach and disinfectant that is activated with hot water, releasing oxygen and sodium carbonate to eliminate stubborn organic stains.", "intro": "Sodium percarbonate is the ecological bleach par excellence. When dissolved in hot water (from 40°C), it decomposes into sodium carbonate (a degreaser and water softener) and hydrogen peroxide (active oxygen), which penetrates the fibers, breaking the bonds of coffee, wine, fruit or sweat stains in a completely biodegradable way.", "healthBenefit": "Eliminates the need to use bleach (sodium hypochlorite), avoiding the inhalation of toxic gases and severe irritation of the respiratory tract and ocular mucous membranes during washing, thus protecting people with multiple chemical sensitivity or asthma.", "time": "10 minutes", "rawDuration": "Dry powder percarbonate: 24 months", "finalDuration": "Dry powder mix: 24 months", "cost": "1.80 €", "metrics": {"economy": 90, "health": 95, "ecosystem": 95}, "shoppingList": [{"name": "Pure Sodium Percarbonate Powder", "price": "1.50 € (500g)"}, {"name": "Finely grated artisanal neutral soap", "price": "0.30 € (100g)"}, {"name": "Airtight storage container", "price": "0.00 € (reciclado)"}], "steps": ["Make sure the container and utensils are completely dry, as moisture activates the percarbonate immediately.", "Finely grate 100g of neutral artisanal soap (it can be castile or coconut soap).", "In the storage container, homogeneously mix the 500g of pure sodium percarbonate with the grated soap.", "Cover tightly and shake well to unify the mixture.", "For direct use on stains: make a paste with a tablespoon of the powder and a little hot water (40-60°C), apply it to the stain and let it sit for 15 minutes before washing.", "For washing machine: add 2 tablespoons of the mixture directly into the washing machine drum next to the clothes and wash at a temperature cycle of at least 40°C to activate the active oxygen."], "altUses": ["Cleaner and deodorizer for clogged toilet bowls or pipes by adding boiling water.", "Whiten tile joints by applying the warm paste with a used toothbrush.", "Wooden cutting board cleaner eliminating persistent odors."], "extraInfo": "Chemically, sodium percarbonate (2Na2CO3·3H2O2) is an adduct of sodium carbonate and hydrogen peroxide. Its ecological advantage over chlorine is that its only decomposition byproducts are oxygen, water and neutral sodium carbonate, without generating bioaccumulative organochlorines.", "comparisonTable": [{"concepto": "Cost per wash", "casero": "€0.09 (2 tablespoons)", "comercial": "0.35 € (oxygenated commercial Quitamanchas)", "diferencia": "Savings of 74%"}, {"concepto": "Toxic byproducts", "casero": "None (Water, Oxygen and Soda)", "comercial": "Synthetic surfactants and phosphonates", "diferencia": "100% Biodegradable"}, {"concepto": "Container stability", "casero": "Stable if stored without moisture", "comercial": "Added chemical stabilizers", "diferencia": "Natural formula"}]}, {"id": "jabon-aceite-usado", "title": "Solid Waste Oil Soap through Saponification", "category": "hogar", "subcategory": "limpieza", "tag": "Cleaning", "image": "assets/images/jabon_ceniza.webp", "views": 480000, "summary": "Manufacture of high hardness soap bars for washing clothes and surfaces through the cold chemical reaction of sodium hydroxide and residual oil.", "intro": "This recipe is the cornerstone of self-sufficiency in the traditional rural home. It transforms a highly polluting waste (used cooking oil) into a highly effective biodegradable cleaning product. Through cold saponification, the caustic soda and fatty acids in the oil are completely transformed into natural soap and glycerin.", "healthBenefit": "It completely replaces synthetic commercial detergents loaded with optical brighteners and artificial perfumes that cause contact dermatitis and irritate sensitive skin by impregnating clothing.", "time": "60 minutes", "rawDuration": "Initial healing: 4-6 weeks", "finalDuration": "Finished pills: More than 24 months", "cost": "0.60 €", "metrics": {"economy": 100, "health": 85, "ecosystem": 100}, "shoppingList": [{"name": "Used cooking oil (strained)", "price": "0.00 € (reciclado)"}, {"name": "Sodium hydroxide (caustic soda flakes)", "price": "0.40 € (135g)"}, {"name": "Distilled or clean rainwater", "price": "0.20 € (300ml)"}, {"name": "Silicone molds or lined cardboard", "price": "0.00 € (reciclado)"}], "steps": ["IMPORTANT: Put on rubber gloves, protective glasses and work in a well-ventilated place. Caustic soda is extremely corrosive.", "Filter the used oil several times with a fine cloth to remove food impurities.", "Very carefully pour the 135g of caustic soda into the 300ml of distilled water (NEVER the other way around). Stir until dissolved. This mixture will reach around 80°C naturally. Let it cool until it drops to about 40°C.", "When the lye and warm oil are at a similar temperature (approx. 40°C), slowly pour the lye into the oil.", "Beat the mixture constantly (preferably with a hand mixer at slow pulses) until you achieve the 'trace' (when the mixture has a texture similar to thick custard and leaves marks when you lift the mixer).", "Pour the trace into the chosen molds and tap them gently against the table to eliminate air bubbles.", "Cover the molds with an old towel to keep warm and let rest for 48 hours. After that time, remove it from the mold with gloves and cut it into tablets. Allow the tablets to cure in a dry, ventilated place for 4 to 6 weeks before using to complete the saponification process."], "altUses": ["Grated for washing machines as an ecological powder detergent.", "Solid dish soap by rubbing the damp scouring pad directly on the tablet.", "All-purpose cleaner by dissolving soap shavings in warm water to scrub floors."], "extraInfo": "Saponification is the alkaline hydrolysis of triacylglycerols. Although pure caustic soda is dangerous to handle initially, once the soap has cured for 40 days, the reaction is 100% complete, so that no active soda remains in the final bar, making it a neutral, safe and very durable soap.", "comparisonTable": [{"concepto": "Cost per pill (150g)", "casero": "0.08 €", "comercial": "€1.20 (Commercial bar soap)", "diferencia": "Savings of 93.3%"}, {"concepto": "Domestic oil waste", "casero": "100% recycling of oils", "comercial": "Pollutant disposal", "diferencia": "Avoid river pollution"}, {"concepto": "Cured and ingredients", "casero": "100% Free of industrial animal fats", "comercial": "Usually contains cheap animal fats (tallowate)", "diferencia": "Local vegetable oil"}]}, {"id": "dentifrico-arcilla-blanca", "title": "White Clay Mineral Toothpaste Powder", "category": "cuerpo", "subcategory": "higiene", "tag": "Hygiene", "image": "assets/images/dentifrico_arcilla.webp", "views": 290000, "summary": "Dry, alkaline mixture of kaolin and sea salts for daily oral hygiene. Low abrasive mechanical cleaning without the need for liquid preservatives.", "intro": "This dry powder toothpaste recovers the old mineral oral cleaning recipes. Based on kaolin (ultra-fine white food grade clay) and sea salts, it naturally neutralizes the acidic pH of the mouth that promotes cavities, mechanically cleans very gently and provides essential minerals to the teeth without attacking the enamel.", "healthBenefit": "It maintains neutral oral pH and eliminates triclosan, microplastics and artificial sweeteners (such as saccharin) that are ingested in small doses with industrial toothpastes, avoiding unnecessary toxins on your mucous membranes.", "time": "5 minutes", "rawDuration": "Unlimited dry storage", "finalDuration": "Finished powder: 24 months (in a sealed bottle)", "cost": "0.50 €", "metrics": {"economy": 90, "health": 85, "ecosystem": 95}, "shoppingList": [{"name": "White clay (kaolin) for oral use", "price": "0.35 € (30g)"}, {"name": "Extra fine ground fine sea salt", "price": "0.05 € (5g)"}, {"name": "Food Grade Baking Soda", "price": "0.10 € (2g)"}, {"name": "Small airtight glass jar", "price": "0.00 € (reciclado)"}], "steps": ["Make sure there are no metallic elements when handling the clay, always use wooden, plastic or ceramic utensils to prevent it from losing its mineral properties.", "Weigh 30g of oral kaolin and add it to the dry bowl.", "Add 5g of extrafine sea salt (coarse common salt could scratch the enamel, it should be ground almost to a powder).", "Add 2g of baking soda (provides extra alkalinity and bacterial control).", "Carefully mix all the powders with a wooden spatula.", "Pour the mixture into the small airtight glass jar.", "To use: moisten the bristles of your toothbrush, gently place them on the powder so that a thin layer adheres, and brush your teeth normally."], "altUses": ["Mineralized mouthwash by dissolving half a teaspoon in half a glass of warm water.", "Gentle polish for small silver objects by applying the dry powder with a microfiber cloth."], "extraInfo": "White clay or kaolin is chemically hydrated aluminum silicate. Its relative dentin abrasiveness index (RDA) is extremely low compared to commercial calcium carbonate or hydrated silica in industrial gels, making it safe for daily brushing if excessive mechanical pressure is not exerted.", "comparisonTable": [{"concepto": "Enamel abrasiveness", "casero": "Very low (ultrafine kaolin)", "comercial": "Medium-high (Commercial hydrated silica)", "diferencia": "More respectful"}, {"concepto": "Ingested chemicals", "casero": "0% (Food grade ingredients)", "comercial": "Triclosan, Sodium Lauryl Sulfate (LSS)", "diferencia": "Safe if swallowed"}, {"concepto": "waste container", "casero": "Infinitely reusable glass jar", "comercial": "Non-recyclable multilayer plastic tubes", "diferencia": "Zero waste"}]}, {"id": "repelente-alcohol-romero", "title": "Rosemary Alcohol Repellent Lotion", "category": "cuerpo", "subcategory": "remedios", "tag": "Remedies", "image": "assets/images/repelente_alcohol_romero.webp", "views": 370000, "summary": "Alcoholic maceration of fresh rosemary branches. It acts as a volatile olfactory barrier for surface application on textiles, window frames and doors.", "intro": "Rosemary (Salvia rosmarinus) is rich in essential oils such as camphor, cineole and alpha-pinene, volatile compounds that insects interpret as environmental warning signals. This lotion uses 96° alcohol as an extraction solvent and rapid evaporation vehicle, leaving a thin natural repellent aromatic layer on clothing or home.", "healthBenefit": "Avoid direct exposure through inhalation to chemical repellents formulated with DEET and petrochemical propellants in aerosol format that affect the central nervous system and harm aquatic fauna.", "time": "10 minutes (plus 15 days of maceration)", "rawDuration": "Maceration: 15 days", "finalDuration": "Repellent lotion: 18 months", "cost": "1.10 €", "metrics": {"economy": 85, "health": 90, "ecosystem": 95}, "shoppingList": [{"name": "96° ethyl alcohol (pharmaceutical use)", "price": "0.90 € (250ml)"}, {"name": "Fresh branches of wild rosemary", "price": "0.20 € (50g)"}, {"name": "Dark glass airtight jar", "price": "0.00 € (reciclado)"}, {"name": "Manual spray container (spray)", "price": "0.00 € (reciclado)"}], "steps": ["Wash fresh rosemary branches well to remove dirt and insects and let them dry completely on absorbent paper.", "Chop the branches with your hands to break the essential oil sacs and place them in the airtight dark glass bottle until it is half full.", "Pour the 250ml of 96° alcohol over the rosemary, covering the branches completely.", "Close the jar tightly and store in a cool, dark place for 15 days.", "Shake the bottle gently once a day to improve the extraction process of active ingredients.", "After 15 days, filter the alcohol with a fine strainer or clean cheesecloth, discarding the branches.", "Pour the rosemary alcohol obtained into the clean spray container and spray on clothing, shoes, curtains, or door frames to repel flying insects."], "altUses": ["Toning and soothing friction to relieve tired legs or joint pain.", "Quick natural disinfectant for hands and surfaces with herbal aroma."], "extraInfo": "The camphor and eucalyptol present in rosemary temporarily block the olfactory and thermal receptors of mosquitoes, making it difficult for them to locate the carbon dioxide and heat emitted by our body. As it does not contain synthetic fixative additives, its effectiveness lies in periodic reapplication.", "comparisonTable": [{"concepto": "Active Ingredient", "casero": "Rosemary essential oil (natural terpenes)", "comercial": "DEET (Synthetic Diethyltoluamide)", "diferencia": "Biodegradable"}, {"concepto": "Impact on the body", "casero": "Harmless dermal absorption", "comercial": "Potential neurotoxic toxicity", "diferencia": "100% Safe"}, {"concepto": "Packaging and propellants", "casero": "Gasless mechanical manual sprayer", "comercial": "Flammable propellant gas (butane/propane)", "diferencia": "Lower carbon footprint"}]}];